import { useState, useEffect, useCallback } from "react";

const D = [
{d:"2026-03-26",e:"🍷",t:"El vino más antiguo de Londres",m:"Gordon's Wine Bar lleva abierto desde 1890, pero su bodega es medieval. Los barriles de roble donde maduran el sherry y el port tienen más años que la mayoría de los edificios. Las paredes están cubiertas de recortes de periódico del siglo XIX. Es el tipo de lugar donde el tiempo se mide en botellas descorchadas."},
{d:"2026-03-27",e:"🧙",t:"King's Cross miente",m:"El exterior de King's Cross que aparece en Harry Potter no es King's Cross. Es St Pancras, la estación de al lado. Los directores decidieron que 'parecía más a King's Cross que King's Cross'. Dos estaciones pegadas, una mintiendo sobre la otra desde 2001."},
{d:"2026-03-28",e:"🏙️",t:"Londres no es una ciudad",m:"Técnicamente, la 'City of London' tiene solo 1.12 millas cuadradas y menos de 10.000 residentes. Lo que llamamos Londres son 32 boroughs, cada uno con su propio alcalde y personalidad. Mudarse a Londres es elegir entre 32 ciudades disfrazadas de una."},
{d:"2026-03-29",e:"🌧️",t:"La lluvia como identidad",m:"Londres tiene menos lluvia anual que Sydney, Miami y Nueva York. Lo que tiene es muchos días nublados y llovizna intermitente. Los londinenses no usan paraguas: usan capas impermeables. A ustedes que les encanta lo gris, les va a fascinar: el cielo londinense es una obra de arte en escala de grises."},
{d:"2026-03-30",e:"👻",t:"Caminás sobre muertos",m:"Debajo de las calles hay más de 6 millones de personas enterradas. Fosas de la peste bubónica están bajo estaciones de subte y oficinas. Cuando excavaron Liverpool Street Station encontraron miles de esqueletos. Cada paso en la City es literalmente sobre historia."},
{d:"2026-03-31",e:"🏟️",t:"Más fútbol que cualquier ciudad",m:"Londres tiene más clubes profesionales que cualquier ciudad del planeta. Solo en la Premier League suele haber 6 o 7 equipos londinenses. Sin hinchar por ninguno, pueden ir al pub del mejor partido cada fin de semana. Libertad futbolística total."},
{d:"2026-04-01",e:"🧀",t:"El queso inglés es mejor de lo que creen",m:"Inglaterra produce más de 700 variedades de queso artesanal. El Tunworth, un camembert inglés, ganó medalla de oro en los World Cheese Awards derrotando a franceses. Van a tener que desaprender prejuicios queseros."},
{d:"2026-04-02",e:"👗",t:"Londres inventó el punk y la minifalda",m:"Mary Quant lanzó la minifalda en King's Road en 1964. Vivienne Westwood inventó el punk en el 430 de la misma calle. McQueen creó la colección más perturbadora de la moda en el East End. La ropa vintage de Londres tiene ADN de revolución."},
{d:"2026-04-03",e:"🌸",t:"El cherry blossom de Londres",m:"Entre finales de marzo y abril, los cherry blossoms explotan en los parques de Londres. Greenwich Park, St James's Park, Regent's Park y especialmente los jardines de Kensington se cubren de rosa y blanco. Los londinenses se vuelven locos con las fotos. Ustedes que aman los árboles blancos: esto les va a volar la cabeza."},
{d:"2026-04-04",e:"🧙",t:"El Callejón Diagon existe",m:"Leadenhall Market tiene la misma estructura de hierro y vidrio desde 1881. La óptica en Bull's Head Passage fue la entrada al Caldero Chorreante. El mercado está en la City, rodeado de banqueros, y se siente más mágico que cualquier set de estudio."},
{d:"2026-04-05",e:"☕",t:"El afternoon tea nació de un ataque de hambre",m:"Anna Russell, Duquesa de Bedford, inventó el afternoon tea en 1840 porque le daba hambre entre almuerzo y cena. Un capricho aristocrático se convirtió en identidad nacional. El hambre como motor cultural."},
{d:"2026-04-06",e:"🏙️",t:"El Tube tiene su propio clima",m:"El subte genera tanto calor por fricción que tiene su propio microclima. En verano, algunas líneas llegan a 35°C. Los londinenses reconocen cada línea por su temperatura y su olor. Van a desarrollar esa habilidad en semanas."},
{d:"2026-04-07",e:"🎵",t:"Abbey Road es un cruce peatonal",m:"El cruce donde los Beatles sacaron la foto es un cruce peatonal común en St John's Wood. Hay una cámara en vivo 24/7. Los autos frenan resignados. Los Beatles tardaron 10 minutos en hacer la toma. Hoy la cola para la foto dura más."},
{d:"2026-04-08",e:"👻",t:"50 Berkeley Square: la casa maldita",m:"Una sirvienta enloqueció ahí. Un noble se encerró en el ático para siempre. Dos marineros pasaron la noche y uno amaneció muerto con los ojos abiertos. Hoy es una librería anticuaria. La habitación del tercer piso sigue cerrada. Está a 15 minutos caminando de Knightsbridge."},
{d:"2026-04-09",e:"🏟️",t:"Wimbledon tiene cola con etiqueta",m:"Wimbledon es el único Grand Slam sobre césped. 'The Queue' es una tradición: la gente acampa la noche anterior con reglas de etiqueta escritas para conseguir entradas. Camping organizado con modales británicos. Fresas con crema incluidas."},
{d:"2026-04-10",e:"🧀",t:"Borough Market tiene 800 años",m:"Existe desde 1276. Ocho siglos de gente comprando comida en el mismo lugar. El dato real: los sábados a las 8am, antes de los turistas, es cuando los londinenses van de verdad. Ahí está la magia."},
{d:"2026-04-11",e:"🌧️",t:"Cosas perfectas para hacer bajo la lluvia",m:"Cuando llueve (y va a llover mucho), Londres se vuelve aún mejor: late en Gordon's Wine Bar con una copa de sherry, una tarde en un bookshop de Charing Cross Road, el British Museum vacío un martes lluvioso, un pub con chimenea en Marylebone. La lluvia no es el enemigo: es el curador de experiencias."},
{d:"2026-04-12",e:"🧙",t:"Rowling fue rechazada 12 veces en Londres",m:"Harry Potter fue rechazado por 12 editoriales londinenses. Bloomsbury lo aceptó porque la hija de 8 años del editor leyó el primer capítulo y exigió el resto. La ciudad que casi lo perdió todo."},
{d:"2026-04-13",e:"☕",t:"Existe un sommelier de té",m:"The Ritz es el único hotel del UK con un Tea Sommelier certificado. 20 variedades, maridaje con cada curso. Es el equivalente de un sommelier de vinos pero con Darjeeling. Para ustedes que aman el maridaje, esto es perfecto."},
{d:"2026-04-14",e:"🏙️",t:"Big Ben no es Big Ben",m:"Big Ben no es el reloj ni la torre. Es la campana de adentro. La torre se llama Elizabeth Tower. La campana se rajó a los pocos meses de instalada en 1859. El sonido que todos reconocen es el sonido de algo roto."},
{d:"2026-04-15",e:"🎵",t:"Los Proms cuestan £8",m:"Los BBC Proms: 8 semanas de conciertos en el Royal Albert Hall. Las Promenade tickets cuestan £8 parados en el arena. Es la puerta de entrada más accesible a la música clásica en vivo que existe."},
{d:"2026-04-16",e:"👻",t:"Jack the Ripper sigue sin nombre",m:"1888. Cinco mujeres. Whitechapel. 137 años después, nadie sabe quién fue. Más de 100 sospechosos propuestos. El pub Ten Bells, donde varias víctimas tomaron su último trago, sigue abierto. Las calles tienen la misma traza."},
{d:"2026-04-17",e:"🩺",t:"Regent's University y Harley Street",m:"Francine va a estudiar en Regent's University, que está en Regent's Park (uno de los parques más lindos de Londres). Y cerca está Harley Street, la calle más famosa del mundo para medicina. Concentra más de 1.500 consultorios y clínicas. Caminar por ahí es caminar por la historia de la medicina británica."},
{d:"2026-04-18",e:"🏟️",t:"Un pub para cada partido",m:"Cada barrio tiene su pub futbolero. The Faltering Fullback en Finsbury Park tiene terraza de tres pisos entre árboles. Sin club, ustedes tienen libertad total: van al pub del mejor partido. La neutralidad es un superpoder."},
{d:"2026-04-19",e:"🧀",t:"Winston Churchill tenía su quesero",m:"Paxton & Whitfield en Jermyn Street es quesero desde el siglo XVIII. Churchill dijo: 'a gentleman only buys his cheese at Paxton & Whitfield.' 200 años vendiendo queso en la misma calle. Está a 20 minutos caminando de Knightsbridge."},
{d:"2026-04-20",e:"🌸",t:"Cuando sale el sol, todo cambia",m:"Cuando sale el sol en Londres, es como si la ciudad entera se transformara. La gente se tira al pasto de los parques, los pubs sacan mesas a la vereda, los picnics aparecen de la nada. Un londinense con sol es una persona diferente. Ustedes que aman esos momentos: Kensington Gardens está literalmente al lado de casa."},
{d:"2026-04-21",e:"🧙",t:"El zoo tiene una placa para Harry",m:"En el Reptile House del London Zoo hay una plaquita donde Harry descubre que habla Parsel. Se filmó frente a la Mamba Negra, no la boa del libro. El zoo está en Regent's Park, donde Francine va a estudiar. Magia y medicina, mismo parque."},
{d:"2026-04-22",e:"☕",t:"Los scones tienen guerra civil",m:"Devon dice cream primero, después jam. Cornwall dice lo opuesto. Es una rivalidad de siglos. Preguntar 'cream first or jam first?' es como preguntar River o Boca. Elijan bando con cuidado."},
{d:"2026-04-23",e:"🏙️",t:"El río esconde 2000 años",m:"El Támesis devuelve objetos romanos, medievales y victorianos. Hay 'mudlarkers' con licencia que buscan tesoros en el barro cuando baja la marea. Monedas romanas, pipas del siglo XVII, huesos humanos. El río no olvida nada."},
{d:"2026-04-24",e:"🎵",t:"Bowie se despidió en Hammersmith",m:"3 de julio de 1973. Bowie retiró a Ziggy Stardust en el Hammersmith Odeon. 'This is the last show we'll ever do.' Nadie sabía si hablaba en serio. El venue (hoy Eventim Apollo) tiene una de las mejores acústicas de Londres."},
{d:"2026-04-25",e:"👻",t:"Hay un cementerio de mascotas en Hyde Park",m:"Detrás de Victoria Gate Lodge hay un diminuto cementerio victoriano de mascotas. Lápidas con nombres como 'Dogsie' y 'Poor Dogsie'. Empezó en 1881 cuando un perro murió y el guarda lo enterró. Más de 300 tumbas. Cuando tengan su perro, van a pasar por ahí y pensar en esto."},
{d:"2026-04-26",e:"👗",t:"Brick Lane cambia de idioma cada siglo",m:"Fue francesa (hugonotes), luego judía, luego bangladesí. Cada ola migratoria dejó su marca. Hoy los carteles están en bengalí e inglés, huele a curry, y el vintage market opera desde una antigua cervecería. Es la calle que mejor cuenta Londres como ciudad de inmigrantes. Como ustedes."},
{d:"2026-04-27",e:"🏟️",t:"Silverstone está a 90 minutos",m:"El GP de Gran Bretaña está a solo 90 minutos en tren. El GP de julio transforma la ciudad: pubs pasan la carrera, eventos temáticos, y si el piloto británico del momento va bien, la energía es comparable a un mundial."},
{d:"2026-04-28",e:"🧀",t:"La 'torta de bodas de queso'",m:"En Gran Bretaña apilan ruedas de queso artesanal de mayor a menor como torta de bodas. Se decora con flores y frutas. No necesitan casarse para pedir una: imaginen eso en un cumpleaños. Con vino, obviamente."},
{d:"2026-04-29",e:"🌧️",t:"El sonido de la lluvia en Knightsbridge",m:"Knightsbridge bajo la lluvia tiene un sonido particular: los autos sobre las calles mojadas, los pasos en las veredas de piedra, las gotas contra los techos de los cafés. Cuando llueva (y va a llover), siéntense en un café de Brompton Road con un flat white y escuchen. Ese sonido va a ser su soundtrack."},
{d:"2026-04-30",e:"🧙",t:"El Ministerio está en Scotland Yard",m:"Great Scotland Yard fue la entrada al Ministerio de Magia. La cabina telefónica roja fue traída para el rodaje. Hoy es una calle gubernamental elegante donde nadie sospecharía que hay magos trabajando debajo."},
{d:"2026-05-01",e:"🏙️",t:"El Great Fire solo mató a 6 personas (oficialmente)",m:"1666. 13.200 casas destruidas, 87 iglesias, 70.000 sin hogar. Solo 6 muertos oficiales. Nadie cree ese número. Lo que sí es cierto: el fuego acabó con la peste al destruir las ratas. Destrucción como cura accidental."},
{d:"2026-05-02",e:"🎵",t:"El jazz londinense es de clase mundial",m:"Ronnie Scott's lleva abierto desde 1959. Miles Davis, Ella Fitzgerald tocaron ahí. Pero lo que hace especial al jazz en Londres es que no se quedó en los 60: Nubya Garcia, Ezra Collective renovaron todo. Londres es la capital del nuevo jazz."},
{d:"2026-05-03",e:"👻",t:"El quirófano más antiguo de Europa",m:"Escondido en el ático de una iglesia en Southwark hay un quirófano de 1822. Antes de la anestesia, sujetaban a los pacientes. Aserrín en el piso para la sangre. Francine: vas a apreciar cuánto avanzó tu profesión cuando lo veas."},
{d:"2026-05-04",e:"👗",t:"Portobello tiene 1 milla de largo",m:"No es un mercado: son varios. Los anticuarios arrancan en Notting Hill Gate, la comida está en el medio, y debajo del Westway empieza el vintage. Cada tramo es un mundo. Los viernes son el mejor día para vintage."},
{d:"2026-05-05",e:"☕",t:"Afternoon tea a 40 pisos",m:"Duck & Waffle, 40 pisos sobre la City, tiene un afternoon tea donde abrís un huevo de pato pintado a mano con bocados adentro. Lobster rolls, waffles de sticky toffee. Las vistas al atardecer son inolvidables."},
{d:"2026-05-06",e:"🌧️",t:"El río que pasa debajo de tu casa",m:"Debajo de Knightsbridge corre el río Westbourne, enterrado desde el siglo XIX. Es el mismo río que le dio nombre al barrio: 'Knightsbridge' era el puente donde los caballeros cruzaban el Westbourne camino a las Cruzadas. Otra versión dice que dos caballeros pelearon sobre el puente y cayeron al río. Nadie sobrevivió. Hoy el río pasa por un tubo de hierro VISIBLE dentro de la estación de Sloane Square. Pueden verlo."},
{d:"2026-05-07",e:"🧙",t:"La varita elige al mago",m:"En Ollivanders, la varita elige al mago. Rowling basó esto en una creencia celta real: los druidas creían que ciertos tipos de madera tenían afinidad con ciertas personas. El acebo (holly, como Holly-wood, como la varita de Harry) representaba protección y coraje. El tejo de Voldemort representaba muerte y renacimiento. La mitología mágica tiene raíces reales en las islas donde van a vivir."},
{d:"2026-05-08",e:"👻",t:"Bedlam: el manicomio era atracción turística",m:"El hospital psiquiátrico de Bethlem (de donde viene la palabra 'bedlam') fue una de las atracciones turísticas más populares del Londres del siglo XVIII. La gente pagaba un penique para mirar a los internos sufrir. Los martes la entrada era gratis. Hoy el edificio existe como hospital moderno en Beckenham y tiene un museo conmovedor llamado Museum of the Mind."},
{d:"2026-05-09",e:"🏙️",t:"Hay un río enterrado debajo de cada barrio",m:"Londres enterró más de 20 ríos debajo de sus calles. El Fleet, el Tyburn, el Westbourne (el de su barrio). Cuando ven una calle que se hunde sin razón aparente o una curva que no tiene sentido urbanístico, probablemente están caminando sobre un río olvidado. La ciudad se construyó sobre agua escondida."},
{d:"2026-05-10",e:"🌸",t:"El árbol más viejo de Londres tiene 2000 años",m:"En los jardines de St Andrew's Church en Totteridge hay un tejo de más de 2.000 años. Estaba ahí antes de que Londres existiera. Antes de que los romanos llegaran. Antes de que alguien dijera 'Londinium'. Ese árbol vio nacer la ciudad que ustedes están por habitar."},
{d:"2026-05-11",e:"👻",t:"En 1814, Londres se inundó de cerveza",m:"Un tanque de más de 6 metros en la cervecería Meux explotó y liberó casi 1.5 millones de litros de cerveza en las calles de St Giles. Casas destruidas, sótanos inundados, 8 personas muertas. Se lo conoce como el London Beer Flood. La cervecería no fue multada: el tribunal lo declaró 'acto de Dios'."},
{d:"2026-05-12",e:"🧙",t:"Hogwarts tiene dirección postal real",m:"Cada carta de aceptación de Hogwarts tiene una dirección real. Pero lo que pocos saben: cuando J.K. Rowling vivía en Edimburgo escribiendo los libros, mandaba las pruebas editoriales a su editora en Bloomsbury, Londres. Todas las decisiones creativas del mundo mágico pasaron por oficinas que hoy pueden visitar en Bedford Square."},
{d:"2026-05-13",e:"🏙️",t:"El gato del gobierno tiene cargo oficial",m:"Larry, el gato de 10 Downing Street, tiene el título oficial de 'Chief Mouser to the Cabinet Office'. Ha sobrevivido a cuatro primeros ministros. Su presupuesto anual es de £100. Es probablemente el empleado gubernamental más estable del Reino Unido."},
{d:"2026-05-14",e:"🌧️",t:"El fog londinense mataba gente",m:"El 'Great Smog' de 1952 mató a más de 12.000 personas en 5 días. La niebla era tan densa que no podías ver tus propios pies. Los cines cerraron porque no se veía la pantalla. Eso llevó al Clean Air Act de 1956, una de las primeras leyes ambientales del mundo. La niebla que asociamos con Londres era en realidad smog letal."},
{d:"2026-05-15",e:"👗",t:"Knightsbridge fue zona de asaltantes",m:"Antes del siglo XIX, Knightsbridge era famoso por ser territorio de highwaymen (asaltantes de camino). Los viajeros que salían de Londres hacia el oeste eran atacados regularmente. En 1736, un lord escribió que el camino entre Kensington y Londres era tan peligroso que vivían 'en la misma soledad que si estuvieran en una roca en medio del océano'. Hoy es el barrio más caro del mundo."},
{d:"2026-05-16",e:"🧙",t:"Platform 9¾ recibe 2 millones de visitas al año",m:"Más personas visitan el carrito de Platform 9¾ en King's Cross que muchos museos nacionales. Es un carrito incrustado en una pared con una bufanda volando. No es una locación de la película (esas se filmaron entre los andenes 4 y 5). Es una invención de marketing de la estación. Y sin embargo, la gente llora ahí. La ficción creó un lugar sagrado real."},
{d:"2026-05-17",e:"🏙️",t:"14 bomberos murieron por no hacer sonar la alarma",m:"Cuando el cuerpo de bomberos se creó en Londres, la primera vez que sonó la alarma fue 30 minutos tarde porque nadie sabía bien cómo. Hoy, cuando suena la alarma de un edificio, el ruido viene de un sistema que el resto del mundo copió de Londres. Las primeras brigadas de bomberos del mundo nacieron de los seguros, no del gobierno: las aseguradoras no querían pagar incendios."},
{d:"2026-05-18",e:"👻",t:"Cromwell fue ejecutado después de muerto",m:"Oliver Cromwell murió en 1658 y fue enterrado en Westminster Abbey. Cuando la monarquía volvió, Charles II ordenó desenterrar su cadáver, darle una 'ejecución ceremonial' póstuma, y clavar su cabeza en una pica. La cabeza estuvo exhibida 24 años sobre Westminster Hall. Hoy hay una piedra en el piso que marca donde estuvo enterrado. La venganza británica es paciente."},
{d:"2026-05-19",e:"🌸",t:"Hyde Park tenía un oso polar en el Támesis",m:"En 1252, el rey Enrique III tenía un oso polar blanco como mascota. Lo dejaba nadar y pescar en el Támesis con una cadena larga. También tenía un elefante y tres leopardos. Todo esto en lo que hoy es la Torre de Londres. A 20 minutos caminando de su casa en Knightsbridge."},
{d:"2026-05-20",e:"🏙️",t:"La estatua más chica de Londres son dos ratones",m:"En Philpot Lane hay una escultura diminuta de dos ratones comiendo queso. Conmemora a dos obreros que se pelearon y cayeron al vacío acusándose mutuamente de robar un sándwich. Después descubrieron que el ladrón era un ratón. Es tan chica que la mayoría pasa sin verla. Londres está llena de historias que nadie mira."},
{d:"2026-05-21",e:"🩺",t:"El primer hospital de Londres eligió Knightsbridge por el aire",m:"En 1733, cuando eligieron ubicación para el nuevo St George's Hospital, lo pusieron en Knightsbridge específicamente porque el aire era 'puro y saludable'. El suelo poroso del barrio drenaba bien y el viento de Hyde Park limpiaba la atmósfera. Francine: tu barrio tiene historia médica. Siempre fue un lugar donde la salud importaba."},
{d:"2026-05-22",e:"👻",t:"Hay casas falsas en Bayswater",m:"En Leinster Gardens, los números 23 y 24 parecen casas victorianas normales. Son fachadas de 1.5 metros de profundidad que esconden infraestructura del Tube detrás. Tienen ventanas pintadas y puertas falsas. Aparecieron en Sherlock de la BBC. Están a 10 minutos caminando de Knightsbridge."},
{d:"2026-05-23",e:"🌧️",t:"George Washington tiene suelo americano bajo sus pies",m:"Cuando Virginia regaló una estatua de George Washington a Londres en 1921, incluyeron tierra americana debajo de la base. Washington había jurado nunca pisar suelo británico. Para no romper su promesa póstuma, técnicamente sigue parado en suelo estadounidense. Está frente a la National Gallery."},
{d:"2026-05-24",e:"🧙",t:"Diagon Alley se lee 'diagonally'",m:"El nombre del Callejón Diagon es un juego de palabras: 'Diagon Alley' suena como 'diagonally', la palabra que Harry dice mal al usar los polvos Floo. 'Knockturn Alley' suena como 'nocturnally'. 'Grimmauld Place' como 'grim old place'. Rowling escondió significado en cada nombre. Los británicos hacen esto con todo: el humor está en las capas."},
{d:"2026-05-25",e:"🏙️",t:"Los taxis negros son un examen de 4 años",m:"Para manejar un black cab en Londres hay que aprobar 'The Knowledge': memorizar 25.000 calles, 320 rutas y 20.000 puntos de interés en un radio de 10km de Charing Cross. Toma entre 2 y 4 años de estudio. Los cerebros de los taxistas londinenses tienen el hipocampo más grande que el promedio. Literalmente les crece el cerebro."},
{d:"2026-05-26",e:"👻",t:"La nursery rhyme es sobre sacrificio de niños",m:"'London Bridge is Falling Down' tiene una teoría oscura: para mantener el puente en pie, se creía que había que enterrar niños en los cimientos como sacrificio humano. Los restos encontrados cuando demolieron versiones antiguas del puente nunca se explicaron del todo. Le van a cantar esa canción a su hijo y ahora saben lo que podría significar."},
{d:"2026-05-27",e:"🌸",t:"Los loros verdes de Kensington Gardens",m:"En los parques de Londres (incluyendo Kensington Gardens, al lado de casa) hay miles de periquitos verdes salvajes. Nadie sabe exactamente cómo llegaron. La leyenda más popular dice que Jimi Hendrix liberó una pareja en Carnaby Street en los 60. Otra dice que se escaparon durante el rodaje de The African Queen. Van a verlos todos los días."},
{d:"2026-05-28",e:"🏙️",t:"Volar un barrilete en Londres es ilegal",m:"La Metropolitan Police Act de 1839 hace ilegal volar barriletes en parques y espacios públicos de Londres. La multa puede llegar a £500. Nadie la aplica, pero técnicamente Mary Poppins estaba cometiendo un crimen. La ley sigue vigente."},
{d:"2026-05-29",e:"👻",t:"El London Bridge original está en Arizona",m:"En 1967, London Bridge se estaba hundiendo. Lo vendieron a un empresario americano por $2.46 millones. Lo desarmaron piedra por piedra, lo mandaron a Arizona y lo reconstruyeron sobre un lago artificial. El puente que hoy cruzan en Londres se inauguró en 1973. El puente 'original' de Londres está en el desierto."},
{d:"2026-05-30",e:"🩺",t:"Las primeras ambulancias del mundo salieron de Londres",m:"El concepto de 'ambulancia' como vehículo dedicado a emergencias médicas se formalizó en Londres. Antes, los heridos eran cargados en carretillas o simplemente dejados. Francine va a trabajar en un sistema de salud que inventó la idea de que vale la pena ir rápido a salvar una vida."},
{d:"2026-05-31",e:"🏙️",t:"En la Gin Craze, cada londinense tomaba 2 litros por semana",m:"Entre 1720 y 1751, Londres atravesó la 'Gin Craze'. El consumo promedio era de 2 pintas de gin por persona por semana. Incluyendo niños. Las tiendas de gin tenían carteles que decían 'Drunk for a penny. Dead drunk for tuppence. Straw provided free.' El gin era más barato que la cerveza. Hoy Londres tiene más gin bars por metro cuadrado que cualquier ciudad del mundo."},
{d:"2026-06-01",e:"🌧️",t:"La primera línea de subte del mundo abrió en Londres",m:"En 1863, la Metropolitan Railway conectó Paddington con Farringdon. Los trenes funcionaban a vapor. Los pasajeros viajaban en vagones abiertos llenos de humo. Cuando propusieron la idea, la gente dijo que era imposible y peligroso. 163 años después, 4 millones de personas viajan en ese sistema cada día. Ustedes van a ser dos de ellas."},
{d:"2026-06-02",e:"👻",t:"Hay un mosquito que solo existe en el Tube",m:"Culex pipiens molestus es una subespecie de mosquito que evolucionó exclusivamente dentro del London Underground. No hiberna, no necesita agua para reproducirse, pica más agresivamente y vive en la oscuridad. La selección natural creó una especie nueva dentro de un sistema de transporte. Darwin estaría orgulloso. Y un poco asqueado."},
{d:"2026-06-03",e:"🏙️",t:"Knightsbridge tuvo una exhibición japonesa antes de que fuera cool",m:"En 1885, Humphreys' Hall en Knightsbridge albergó una exhibición de cultura japonesa con una aldea tradicional reconstruida completa. 250.000 personas fueron en los primeros meses. La experiencia supuestamente inspiró a W.S. Gilbert a escribir 'The Mikado'. Knightsbridge siempre fue un lugar donde Oriente y Occidente se encontraban."},
{d:"2026-06-04",e:"🧙",t:"Harry Potter salvó un hospital de niños",m:"J.M. Barrie (el autor de Peter Pan, no Rowling) donó los derechos de autor de Peter Pan a Great Ormond Street Hospital en 1929. Cada película, libro y producto de Peter Pan genera ingresos para ese hospital de niños. Rowling continuó esa tradición: donó millones a hospitales infantiles. La literatura británica tiene una veta generosa que corre paralela a la magia."},
{d:"2026-06-05",e:"🌸",t:"14 comensales cenaron en la cima de la columna de Nelson",m:"Antes de poner la estatua de Nelson arriba de la columna en Trafalgar Square en 1842, 14 albañiles subieron y cenaron en la cima. Comieron arriba de una columna de 52 metros de alto, en el medio de Londres, como si fuera lo más normal del mundo. El dato que completa la historia: Hitler quería desarmar esa columna y llevarla a Berlín."},
{d:"2026-06-06",e:"👻",t:"El zoológico de Londres cobraba la entrada con perros y gatos",m:"En el siglo XVIII, el zoológico estaba en la Torre de Londres. La entrada era gratuita si traías un perro o un gato. ¿Para qué? Para alimentar a los leones. Cuando tengan su perro grande y paseen por la Torre, piensen que hace 300 años ese perro habría sido almuerzo."},
{d:"2026-06-07",e:"🏙️",t:"Hay más restaurantes indios en Londres que en Mumbai",m:"Londres tiene más de 3.600 restaurantes indios, más que Mumbai o Delhi. El chicken tikka masala (que técnicamente es un invento británico, no indio) es considerado el plato nacional no oficial del Reino Unido. La comida india en Londres no es 'étnica': es parte fundamental de la identidad gastronómica del país."},
{d:"2026-06-08",e:"🌧️",t:"El Támesis estaba tan contaminado que fue declarado biológicamente muerto",m:"En los años 60, el nivel de contaminación del Támesis era tan alto que lo declararon biológicamente extinto. No había vida. Hoy tiene más de 125 especies de peces y focas que nadan hasta el centro. Es una de las historias de recuperación ambiental más exitosas del mundo. El río que va a ser su vecino resucitó."},
{d:"2026-06-09",e:"🧙",t:"El Sombrero Seleccionador casi no existió",m:"Rowling originalmente pensó en un sistema diferente para clasificar a los estudiantes en las casas. El Sombrero Seleccionador fue una idea de último momento que cambió toda la saga. Si no hubiera existido, no habría 'I'm a Gryffindor' ni tests de personalidad basados en las casas. Una decisión de escritura cambió la cultura pop de una generación."},
{d:"2026-06-10",e:"🏙️",t:"Pop Goes the Weasel es sobre empeñar un traje para tomar",m:"La nursery rhyme 'Pop Goes the Weasel' es sobre empeñar ('pop') un traje ('weasel and stoat' = coat en slang cockney) para pagar bebida. 'Up and down the City Road, in and out the Eagle' se refiere al pub Eagle en City Road, que existe hoy con la letra de la canción en un cartel afuera."},
{d:"2026-06-11",e:"👻",t:"Epping Forest tiene cuerpos que nadie encuentra",m:"Epping Forest, en el noreste de Londres, fue durante décadas el lugar favorito de los gángsters del East End para deshacerse de cuerpos. Es tan grande y denso que la Corporation of London admitió que no hay forma de evitar que sigan apareciendo cadáveres. A pesar de esto, es uno de los bosques más populares para pasear. Con o sin perro."},
{d:"2026-06-12",e:"🌸",t:"Londres es técnicamente un bosque",m:"Londres tiene más de 8 millones de árboles. Bajo la definición de las Naciones Unidas, eso la califica como 'bosque urbano'. Casi el 47% de la superficie de la ciudad es verde. Es más verde que muchas ciudades que se venden como 'naturaleza'. Kensington Gardens, al lado de casa, es parte de ese bosque."},
{d:"2026-06-13",e:"🩺",t:"El primer anestésico se probó en Londres",m:"En 1846, en el University College Hospital de Londres, se realizó la primera operación con éter en Europa. El paciente, Frederick Churchill, tuvo una pierna amputada sin sentir dolor. Fue un momento que cambió la medicina para siempre. Francine: vas a formarte en la ciudad donde la cirugía sin dolor empezó."},
{d:"2026-06-14",e:"🏙️",t:"5 estaciones de Tube tienen nombre de pub",m:"Angel, Royal Oak, Elephant & Castle, Manor House y Swiss Cottage: todas son estaciones del Tube que tomaron su nombre de pubs cercanos. No al revés. Los pubs existían primero. En Londres, los bares definen la geografía."},
{d:"2026-06-15",e:"👻",t:"Debajo de Cleopatra's Needle hay una cápsula del tiempo de 1878",m:"Debajo del obelisco egipcio en el Embankment enterraron una cápsula con cigarros, una navaja de afeitar, un retrato de la Reina Victoria, copias de 10 diarios y fotos de las '12 bellezas inglesas del momento'. Nadie sabe si algún día la van a abrir."},
{d:"2026-06-16",e:"🧙",t:"El expreso de Hogwarts es real (y se puede tomar)",m:"El Jacobite Steam Train en Escocia (Fort William a Mallaig) cruza el viaducto de Glenfinnan que aparece en las películas. Es un tren de vapor real que hace la ruta del Hogwarts Express. Desde Londres, es un viaje de un fin de semana largo. Es la excursión perfecta para su primer año."},
{d:"2026-06-17",e:"🌧️",t:"La razón por la que Londres es gris",m:"Londres no tiene mucha lluvia comparada con otras ciudades. Lo que tiene es muchos días nublados porque está en una cuenca baja rodeada de colinas suaves donde el aire húmedo del Atlántico se estanca. El cielo gris no es accidente: es geografía. Y ese gris que ustedes aman es la personalidad meteorológica de la ciudad."},
{d:"2026-06-18",e:"🏙️",t:"Voltaire, Van Gogh, Freud, Marx y Ho Chi Minh vivieron en Londres",m:"En diferentes momentos de la historia, todos eligieron Londres como refugio. Marx escribió el Manifiesto Comunista arriba del pub Red Lion en Great Windmill Street. Gandhi estudió derecho en Inner Temple. Freud huyó de los nazis y murió en Hampstead. La ciudad que van a habitar fue hogar temporal de gente que cambió el mundo."},
{d:"2026-06-19",e:"👻",t:"La primera persona en ser fotografiada muerta fue londinense",m:"La fotografía post-mortem (fotografiar a los muertos como si estuvieran vivos) fue enormemente popular en la Londres victoriana. Era la única forma que muchas familias tenían de conservar la imagen de un ser querido. Las fotos se tomaban con los ojos abiertos, sentados en sillas, a veces rodeados de familiares vivos. Es perturbador y profundamente humano."},
{d:"2026-06-20",e:"🌸",t:"Hay un jardín venenoso en Londres",m:"El Alnwick Garden (técnicamente en Northumberland, pero hay jardines venenosos en Londres también, como el del Chelsea Physic Garden) cultiva plantas que pueden matar: belladona, estricnina, ricino. Están detrás de rejas. Los guías te cuentan cómo cada planta fue usada históricamente para asesinar. Es jardinería con ADN criminal."},
{d:"2026-06-21",e:"🏙️",t:"El día más largo del año en Londres tiene 16 horas de luz",m:"El solsticio de verano en Londres significa que amanece a las 4:43am y oscurece a las 9:21pm. Son más de 16 horas de luz. Comparado con Buenos Aires en invierno (que es cuando ustedes llegan), la diferencia va a ser brutal. El primer verano londinense los va a sorprender: sale el sol y no se va."},
{d:"2026-06-22",e:"👻",t:"Benjamin Franklin tenía cadáveres en su sótano de Londres",m:"En 1998, durante una renovación de la casa de Benjamin Franklin en 36 Craven Street (la única casa de Franklin que sobrevive en el mundo), encontraron más de 1.200 restos humanos en el sótano. Se cree que su amigo William Hewson hacía disecciones anatómicas ilegales ahí. Franklin probablemente sabía. La casa hoy es un museo."},
{d:"2026-06-23",e:"🧙",t:"El pub donde Hagrid le cuenta a Harry que es mago",m:"En los libros, Hagrid y Harry pasan por un pub llamado The Leaky Cauldron antes de entrar a Diagon Alley. Rowling se inspiró en varios pubs victorianos oscuros de Londres. El más probable: un pub en Leadenhall Market que hoy no existe como tal, pero el pasaje que usaron para filmar sigue intacto."},
{d:"2026-06-24",e:"🏙️",t:"Karl Marx escribió el Comunismo arriba de un pub londinense",m:"Marx redactó partes del Manifiesto Comunista en una habitación sobre el Red Lion pub en Great Windmill Street, Soho. El pub sigue abierto. Pueden tomar una pinta donde se gestó una ideología que dividió al mundo. La ironía de que el capitalismo pague las cervezas no se les va a escapar."},
{d:"2026-06-25",e:"🌧️",t:"El olor después de la lluvia en Londres es diferente",m:"Petrichor: el olor de la tierra mojada después de la lluvia. En Londres, el petrichor se mezcla con el olor de los parques, el asfalto victoriano y el aire del Támesis. Es un olor único que no existe en ninguna otra ciudad. Cuando lo sientan por primera vez, van a saber que están en casa."},
{d:"2026-06-26",e:"👻",t:"Los body snatchers de Londres robaban cadáveres para la ciencia",m:"En el siglo XIX, la demanda de cadáveres para estudio médico era tan alta que surgieron los 'resurrection men': ladrones de tumbas profesionales. Desenterraban cuerpos frescos y los vendían a escuelas de medicina. Francine: la profesión médica en la que te estás formando tiene un pasado oscuro. Los cirujanos de la época necesitaban esos cuerpos para aprender."},
{d:"2026-06-27",e:"🌸",t:"St James's Park tiene pelícanos desde 1664",m:"En 1664, el embajador ruso le regaló pelícanos a Charles II. Desde entonces, hay pelícanos en St James's Park. Se alimentan todos los días a las 2:30pm. Llevan 362 años viviendo en el centro de Londres. Son probablemente los residentes más antiguos de la ciudad."},
{d:"2026-06-28",e:"🏙️",t:"Dickens caminaba 30km por noche por Londres",m:"Charles Dickens sufría de insomnio severo. Su solución: caminar por Londres de noche, a veces 30km de una sola vez. Esas caminatas nocturnas le dieron el material para sus descripciones de la ciudad. Cuando caminen por Londres de noche, están viendo lo que Dickens veía. Las calles son diferentes, pero la energía nocturna de la ciudad es la misma."},
{d:"2026-06-29",e:"🧙",t:"Rowling escribió el final de Harry Potter en un hotel de Edimburgo",m:"Rowling terminó Las Reliquias de la Muerte en la habitación 552 del Balmoral Hotel en Edimburgo. Dejó un mensaje escrito en un busto de mármol: 'JK Rowling finished writing Harry Potter and the Deathly Hallows in this room (552) on 11th Jan 2007'. El hotel mantiene la habitación como suite especial. El viaje en tren de Londres a Edimburgo dura 4.5 horas."},
{d:"2026-06-30",e:"🏙️",t:"Los zorros de Londres son más urbanos que los perros",m:"Londres tiene más de 10.000 zorros que viven permanentemente en la ciudad. Cruzan calles, duermen en jardines, revisan basura con total confianza. Son nocturnos pero cada vez más visibles de día. En Knightsbridge los van a ver seguido. No son agresivos. Son vecinos."},
{d:"2026-07-01",e:"🌧️",t:"Cuando llueve en Knightsbridge, Harrods se llena",m:"No es una metáfora: cuando empieza a llover, la gente de Knightsbridge se mete en Harrods como si fuera un refugio. La tienda funciona como un living gigante del barrio. 5 minutos de casa, 330 departamentos, calefacción perfecta. Van a hacer esto. Muchas veces."},
{d:"2026-07-02",e:"👻",t:"Hay una estación de Tube abandonada embrujada por un dios egipcio",m:"La estación de British Museum (cerrada en 1933) supuestamente está embrujada por el fantasma de Amun-Ra. En 1935 desaparecieron dos mujeres en la estación vecina de Holborn. Rumores de un túnel secreto entre la estación y la sala egipcia del museo nunca fueron confirmados. Sonidos y avistamientos de una figura en taparrabos continúan."},
{d:"2026-07-03",e:"🏙️",t:"Knightsbridge era 'un nombre sin pueblo'",m:"En 1857, un residente escribió que Knightsbridge era 'un nombre sin pueblo' porque caía incómodamente entre cuatro parroquias diferentes. No era un pueblo, ni un barrio, ni nada definido: era simplemente el área alrededor de un puente. De la nada, se convirtió en una de las direcciones más caras del planeta."},
{d:"2026-07-04",e:"🧙",t:"La Cámara Secreta se inspiró en una leyenda real de Londres",m:"La idea de una cámara oculta debajo de un edificio antiguo no es invención de Rowling. Londres tiene cámaras subterráneas reales debajo de iglesias, palacios y edificios medievales. La Cámara del Parlamento que Guy Fawkes intentó volar existe debajo de Westminster. La ficción de Harry Potter es menos fantástica de lo que parece cuando vivís en Londres."},
{d:"2026-07-05",e:"🌸",t:"En verano, Hyde Park tiene deck chairs como una playa",m:"De junio a septiembre, Hyde Park despliega deck chairs (sillas de playa de lona) por todo el césped. Se pagan por hora. La gente se sienta a leer, dormir, tomar sol. Es la versión londinense de ir a la playa: sin mar, sin arena, con pasto y patos. Todo esto a 3 minutos de su casa."},
{d:"2026-07-06",e:"👻",t:"Los túneles de Churchill están debajo de Westminster",m:"El Cabinet War Rooms, el bunker donde Churchill dirigió la guerra, está intacto debajo de Westminster. Las tazas de té siguen en las mesas. Los mapas en las paredes. Los teléfonos en los escritorios. Todo tal cual quedó en 1945. Es como si la guerra terminara ayer. Se puede visitar."},
{d:"2026-07-07",e:"🏙️",t:"St Paul's tiene piñas en vez de cruces",m:"Mirá las dos torres de St Paul's Cathedral. Arriba de cada una no hay una cruz: hay una piña. Christopher Wren las puso como símbolo de hospitalidad, paz y prosperidad. Originalmente quería poner una piña de piedra de 18 metros en la cúpula principal. Le dijeron que no."},
{d:"2026-07-08",e:"🧙",t:"El Patronus de Rowling es una garza",m:"Rowling dijo que si tuviera un Patronus sería una garza, el mismo animal que vive en Regent's Park (donde Francine va a estudiar). Las garzas grises de Regent's Park son enormes, silenciosas y majestuosas. Van a verlas paradas junto al lago como estatuas vivientes."},
{d:"2026-07-09",e:"🌧️",t:"Los paraguas son un insulto social en Londres",m:"Usar paraguas en Londres es perfectamente aceptable pero sutilmente despreciado por los londinenses auténticos. Caminar bajo la lluvia sin paraguas es una declaración de pertenencia. La llovizna londinense rara vez justifica un paraguas de verdad. Cuando dejen de abrir el paraguas, van a saber que se convirtieron en londinenses."},
{d:"2026-07-10",e:"🏙️",t:"El piso más caro del mundo está en su barrio",m:"One Hyde Park en Knightsbridge vendió un departamento por £100 millones en 2007. El edificio tiene piscina privada, cine, servicio de concierge 24/7 y vidrios antibalas. Los vecinos incluyen oligarcas y miembros de familias reales. Es el edificio más caro del mundo. Está al lado de su casa."},
{d:"2026-07-11",e:"👻",t:"Hay un túnel secreto entre el Parlamento y un pub",m:"Según la leyenda, hay un túnel que conecta las Houses of Parliament con el St Stephen's Tavern del otro lado de la calle. Los parlamentarios supuestamente lo usaban para ir a tomar sin ser vistos. El pub sigue abierto. El túnel supuestamente también. Los políticos británicos siempre priorizaron el acceso a la cerveza."},
{d:"2026-07-12",e:"🌸",t:"Los ciervos de Richmond Park no le tienen miedo a nadie",m:"Los 630+ ciervos de Richmond Park (a 30 min de Knightsbridge) llevan viviendo ahí desde que Charles I los trajo en 1637. No son domesticados pero tampoco huyen. Se acercan, te miran, y siguen su camino. En otoño, el bramido de los machos en celo se escucha desde kilómetros."},
{d:"2026-07-13",e:"🏙️",t:"Londres celebra que alguien INTENTÓ volar el Parlamento",m:"El 5 de noviembre, Bonfire Night, es la celebración de que Guy Fawkes FALLÓ en volar el Parlamento en 1605. Queman muñecos de él, lanzan fuegos artificiales. Es una fiesta nacional que celebra un fracaso. Solo los británicos festejarían que alguien no pudo hacer algo."},
{d:"2026-07-14",e:"🧙",t:"MinaLima diseñó hasta los periódicos que nadie lee en la película",m:"El equipo de diseño MinaLima creó cada pieza de papel visible en las películas: el Profeta, las cartas de Hogwarts, las etiquetas de las pociones, los mapas. Incluso las páginas que aparecen 0.3 segundos en pantalla están completamente diseñadas y escritas. La obsesión por el detalle es muy londinense."},
{d:"2026-07-15",e:"👻",t:"En Knightsbridge, las bodas eran ilegales y secretas",m:"Antes de 1753, la capilla de Knightsbridge era famosa por celebrar 'matrimonios robados': bodas ilegales y secretas para parejas que huían o no tenían permiso. Los registros parroquiales tienen notas como 'gran secreto' o 'secreto de por vida' junto a los nombres. Su barrio elegante tiene un pasado de rebeldía romántica."},
{d:"2026-07-16",e:"🏙️",t:"Los black cabs tienen el radio de giro de un tanque",m:"Los black cabs de Londres están diseñados con un radio de giro de 7.6 metros para poder dar la vuelta en la rotonda de Savoy Hotel. Es un requisito de diseño que existe desde los carruajes tirados por caballos. Cada taxi negro que vean es una máquina de ingeniería diseñada alrededor de una rotonda de hotel."},
{d:"2026-07-17",e:"🌧️",t:"Hay un río subterráneo que pasa por un tubo VISIBLE en Sloane Square",m:"El río Westbourne (el que pasa debajo de Knightsbridge) cruza la estación de Sloane Square por un tubo de hierro verde que se ve claramente sobre las vías. Es uno de los pocos lugares donde pueden ver un río enterrado. Está a una estación de Tube de su casa."},
{d:"2026-07-18",e:"🧙",t:"Rowling planeó matar a Arthur Weasley",m:"Rowling confesó que originalmente planeaba matar a Arthur Weasley en La Orden del Fénix. Cambió de opinión porque necesitaba mantener al menos un padre bueno en la historia. Ron iba a quedarse sin papá. La decisión de Rowling de dejarlo vivir cambió todo el arco emocional de los últimos tres libros."},
{d:"2026-07-19",e:"🏙️",t:"La primera foto de la historia se tomó desde una ventana",m:"Esto no es de Londres, pero la cultura fotográfica británica es la más antigua del mundo. Fox Talbot, inglés, inventó un proceso fotográfico casi al mismo tiempo que Daguerre en Francia. La disputa sobre quién inventó la fotografía es una pelea franco-inglesa que sigue hasta hoy. Como la del champagne."},
{d:"2026-07-20",e:"👻",t:"El Támesis arrastra cuerpos hasta hoy",m:"La policía del Támesis (fundada en 1798, la fuerza policial más antigua del mundo) recupera cuerpos del río regularmente. Algunos son accidentes, algunos suicidios, algunos nunca se explican. El río que van a cruzar todos los días tiene una relación con la muerte que Londres prefiere no publicitar."},
{d:"2026-07-21",e:"🌸",t:"El perro más famoso de Londres se llamaba Greyfriars Bobby",m:"No es de Londres sino de Edimburgo, pero la cultura británica del perro es la más intensa del mundo. Los pubs tienen bowls con agua, los taxis aceptan perros, los parques tienen zonas específicas. Cuando tengan su perro grande, van a descubrir que ser 'dog parent' en Londres es una identidad social completa."},
{d:"2026-07-22",e:"🏙️",t:"El espresso martini se inventó en Londres",m:"El barman Dick Bradsell inventó el espresso martini en el Soho de los 80 cuando una modelo (supuestamente Kate Moss, pero nadie confirma) le pidió un trago que la despertara y la emborrachara al mismo tiempo. Un pedido de viernes a la noche en un bar de Londres creó uno de los cócteles más populares del mundo."},
{d:"2026-07-23",e:"🧙",t:"Snape es el personaje más complejo de la literatura contemporánea",m:"Alan Rickman (que nació en Hammersmith, Londres) fue el único actor al que Rowling le contó el arco completo de Snape antes de que se publicaran los libros. Rickman llevó ese secreto durante 10 años de filmación. Cada mirada, cada gesto que hizo en las películas sabía cómo terminaba. Los otros actores no entendían por qué actuaba así."},
{d:"2026-07-24",e:"🌧️",t:"Los londinenses miden la felicidad en grados",m:"Cuando la temperatura sube de 18°C, los londinenses consideran que es 'un día hermoso'. A 22°C ya es 'una ola de calor'. A 25°C los diarios sacan titulares. Viniendo de Argentina, van a recalibrar completamente su termómetro emocional. 14°C con sol va a ser 'buen día'. Y lo van a sentir así."},
{d:"2026-07-25",e:"👻",t:"Newgate Prison tenía espectadores VIP para las ejecuciones",m:"Frente a la prisión de Newgate (hoy el Old Bailey, la corte criminal más famosa del mundo), los ricos alquilaban ventanas de los edificios de enfrente para ver las ejecuciones con comodidad. Los precios subían según la fama del condenado. Era entretenimiento premium."},
{d:"2026-07-26",e:"🏙️",t:"Knightsbridge tiene la embajada de Francia",m:"La Embajada de Francia está en Knightsbridge, en un edificio de tres pisos construido entre 1899 y 1902. Para Francine, que es francesa, esto tiene un significado especial: su país tiene representación diplomática a metros de donde van a vivir. No están lejos de Francia. Francia está literalmente al lado."},
{d:"2026-07-27",e:"🌸",t:"Hyde Park fue campo de duelos",m:"Hasta el siglo XVIII, Hyde Park era el lugar favorito de Londres para los duelos. Aristócratas, militares y caballeros ofendidos se citaban al amanecer con espadas o pistolas. Hoy la gente hace yoga en el mismo pasto donde la gente se mataba por honor. El parque al lado de casa tiene sangre noble en la tierra."},
{d:"2026-07-28",e:"🧙",t:"Dobby murió en una playa real",m:"La escena de la muerte de Dobby en Las Reliquias de la Muerte se filmó en Freshwater West Beach en Gales. Los fans dejaron tantos calcetines y memoriales en la playa que las autoridades tuvieron que intervenir. Es a 4 horas de Londres en auto. Algún fin de semana, vayan."},
{d:"2026-07-29",e:"🏙️",t:"La estación de Tube más profunda está a 58 metros",m:"Hampstead station está a 58 metros bajo tierra. El viaje en ascensor tarda casi un minuto. Cuando bajen, piensen que están más profundo que un edificio de 15 pisos. Y que arriba de sus cabezas hay capas de historia, huesos, ríos enterrados y secretos que Londres esconde debajo de sus pies."},
{d:"2026-07-30",e:"👻",t:"Los teatros del West End están todos embrujados",m:"Casi todos los teatros del West End reportan actividad paranormal. El Theatre Royal Drury Lane tiene al 'Man in Grey', un esqueleto encontrado en una pared con un cuchillo en las costillas. El Adelphi tiene a William Terriss. El Garrick tiene su propio fantasma. Si van al teatro en Londres, técnicamente nunca están solos en la sala."},
{d:"2026-07-31",e:"🌸",t:"Mañana empieza agosto y los parques están en su máximo",m:"Agosto en los parques de Londres es cuando todo está en su punto más verde, más vivo, más lleno de gente. Kensington Gardens al lado de casa, el Serpentine Lido abierto, deck chairs bajo los árboles. Faltan 3 meses. Los parques los están esperando."},
{d:"2026-08-01",e:"🏙️",t:"Londres fue la capital de 8 países durante la guerra",m:"Durante la Segunda Guerra Mundial, los líderes exiliados de Noruega, Polonia, Bélgica, Francia, Países Bajos, Grecia, Yugoslavia y Checoslovaquia gobernaron desde Londres. Fue capital de 8 países simultáneamente. La ciudad que van a habitar fue refugio de medio continente."},
{d:"2026-08-02",e:"👻",t:"Hay un barco bomba en el Támesis que podría explotar",m:"El SS Richard Montgomery se hundió en 1944 en el estuario del Támesis con 1.440 toneladas de municiones. Los mástiles todavía sobresalen del agua. Si explota, destruiría Sheerness. El cartel de entrada al pueblo dice: 'Welcome to Sheerness, you'll have a blast.' El humor británico aplica incluso al peligro existencial."},
{d:"2026-08-03",e:"🌧️",t:"Los pubs son el corazón de todo",m:"Un pub no es un bar. Es el living de la comunidad. Los británicos socializan ahí como los argentinos en casa. El pub es donde se miran partidos, se celebran cumpleaños, se lloran pérdidas, se cierran negocios y se hacen amigos. Encontrar 'su' pub va a ser uno de los momentos más importantes de la mudanza."},
{d:"2026-08-04",e:"🧙",t:"Los magos de Harry Potter usan el subte",m:"En los libros, Arthur Weasley se fascina con el sistema de tickets del Tube. Los magos usan transporte muggle cuando necesitan pasar desapercibidos. Cada vez que usen la Oyster Card, técnicamente están haciendo lo mismo que un mago de incógnito en el mundo muggle."},
{d:"2026-08-05",e:"🏙️",t:"Hay más de 300 idiomas en Londres",m:"Londres es la ciudad más lingüísticamente diversa del mundo. Más de 300 idiomas se hablan cotidianamente. Francine habla francés. Lucca habla español. Ambos hablan inglés. En Londres, hablar tres idiomas no es excepcional: es promedio."},
{d:"2026-08-06",e:"🌸",t:"Los parques de Londres suenan diferente según la hora",m:"A las 5am: pájaros. A las 7am: runners. A las 9am: madres con cochecitos. A las 12pm: oficinistas almorzando. A las 4pm: niños de colegio. A las 7pm: parejas caminando. A las 10pm: zorros. Los parques tienen un soundtrack que cambia cada hora. El de Kensington Gardens va a ser el suyo."},
{d:"2026-08-07",e:"👻",t:"El fantasma más visto de Londres es una enfermera",m:"En St Thomas' Hospital (donde Florence Nightingale fundó la primera escuela de enfermería del mundo), múltiples testigos han reportado ver a una enfermera victoriana recorriendo los pasillos. Francine: el fantasma de tu profesión cuida los hospitales de Londres."},
{d:"2026-08-08",e:"🏙️",t:"Los pisos de Knightsbridge se venden sin que nadie viva en ellos",m:"Un fenómeno de Knightsbridge: muchos departamentos de ultra-lujo están vacíos. Son inversiones de extranjeros que nunca los habitan. Hay cuadras enteras donde las luces nunca se encienden. Ustedes van a ser de los pocos que realmente VIVEN en Knightsbridge. Eso los hace más londinenses que la mayoría de sus vecinos."},
{d:"2026-08-09",e:"🧙",t:"Hogwarts no tiene WiFi",m:"Rowling explicó que la tecnología muggle no funciona en Hogwarts porque hay demasiada magia en el aire. Es una regla del mundo mágico que tiene un paralelo real: muchos castillos y edificios antiguos de Gran Bretaña genuinamente tienen mala señal de celular por el grosor de las paredes de piedra. La magia es de piedra."},
{d:"2026-08-10",e:"🌧️",t:"El otoño en Londres empieza antes de lo que creen",m:"A mediados de septiembre, los parques ya empiezan a cambiar de color. Para cuando lleguen en octubre, los árboles van a estar dorados. Kensington Gardens desde la ventana de su casa va a parecer un cuadro de Turner. El primer otoño londinense es el más bello. Sobre todo para dos personas que aman lo gris."},
{d:"2026-08-11",e:"🏙️",t:"Los nombres de las calles cuentan historias",m:"Bleeding Heart Yard: donde una mujer fue encontrada con el corazón arrancado. Crutched Friars: donde vivían los monjes con muletas. Rotten Row: del francés 'Route du Roi' (camino del rey), corrompido por la pronunciación inglesa. Cada calle de Londres esconde una historia en su nombre. Solo hay que mirar el cartel."},
{d:"2026-08-12",e:"👻",t:"Florence Nightingale tenía un búho de mascota llamado Athena",m:"Nightingale rescató un pequeño búho en Grecia y lo llamó Athena. Lo llevaba en su bolsillo. El búho murió justo antes de que ella partiera a Crimea. Es un detalle tierno de una mujer que cambió la medicina. Francine: la fundadora de tu profesión amaba los animales tanto como ustedes."},
{d:"2026-08-13",e:"🌸",t:"Las ardillas de Londres son todas grises por una razón",m:"Las ardillas grises (americanas) reemplazaron casi totalmente a las ardillas rojas (nativas) en Londres. Fueron introducidas en 1876 como novedad en parques de mansiones. Hoy hay más de 2 millones en Gran Bretaña. Es una historia de invasión ecológica en tiempo real. Las van a ver todos los días en Kensington Gardens."},
{d:"2026-08-14",e:"🏙️",t:"Hay un parking space en Knightsbridge que vale £300.000",m:"En Knightsbridge, un espacio de estacionamiento se vendió por £300.000. No un garaje. Un espacio. Al aire libre. Con un contrato de 94 años. El metro cuadrado más caro del mundo no es un departamento: es donde estacionás el auto."},
{d:"2026-08-15",e:"🧙",t:"La última palabra de la saga es 'well'",m:"Las últimas palabras de Harry Potter y las Reliquias de la Muerte son 'All was well.' Tres palabras que cierran 7 libros, 4.224 páginas y una década de escritura. Rowling dijo que escribió esa frase años antes de terminar el libro. Sabía cómo terminaba antes de saber cómo llegaba. Ojalá sus primeros meses en Londres terminen igual: all was well."},
{d:"2026-08-16",e:"👻",t:"Hay cuerpos debajo de cada iglesia de Londres",m:"Casi todas las iglesias del centro de Londres tienen criptas con restos humanos debajo. Muchas funcionan hoy como cafés, galerías o espacios de eventos. Pueden tomar un café sentados literalmente sobre tumbas medievales. En la cripta de St Martin-in-the-Fields hay un restaurante. Los huesos están debajo del piso."},
{d:"2026-08-17",e:"🌧️",t:"El sonido del Tube llegando es único en el mundo",m:"El rugido del aire que empuja el tren por el túnel antes de que aparezca, seguido del silbido de los frenos. Ese sonido no existe en ningún otro subte del mundo porque los túneles de Londres son más estrechos y redondos. Es un sonido que van a asociar con llegar a algún lado. Siempre."},
{d:"2026-08-18",e:"🏙️",t:"La Embajada de Francia en Knightsbridge es un pedazo de su vida",m:"Para Francine: la Embajada de Francia en Knightsbridge (58 Knightsbridge) es donde van a hacer trámites, votar y sentirse en Francia sin irse de casa. Está a metros. Esa cercanía no es casualidad: Knightsbridge siempre tuvo una conexión fuerte con Francia. Van a escuchar francés en los cafés de Brompton Cross todo el tiempo."},
{d:"2026-08-19",e:"🧙",t:"El mapa del merodeador funciona como el subte",m:"Rowling dijo que diseñó el mapa del merodeador con la misma lógica que el mapa del Tube de Londres: no es geográficamente preciso, pero muestra conexiones y movimientos. Harry Beck, el diseñador del mapa del Tube en 1931, creó una forma de ver una ciudad que Rowling usó para ver un castillo."},
{d:"2026-08-20",e:"🌸",t:"Los atardeceres de octubre en Londres son los mejores del año",m:"La combinación de la latitud norte, la humedad del aire y la contaminación lumínica moderada hace que los atardeceres de octubre en Londres sean espectaculares. Rojos, naranjas, púrpuras. Desde Parliament Hill o desde Waterloo Bridge. Van a llegar justo para la mejor época de cielos."},
{d:"2026-08-21",e:"👻",t:"Los espías de la Guerra Fría se encontraban en la Brompton Oratory",m:"La Brompton Oratory (la iglesia barroca grande en Brompton Road, a 5 minutos de Knightsbridge) fue usada como punto de encuentro por espías soviéticos durante la Guerra Fría. Los agentes dejaban mensajes en puntos específicos de la iglesia. Está a metros de su casa. Pueden entrar cuando quieran. Ya no hay espías. Probablemente."},
{d:"2026-08-22",e:"🏙️",t:"40 días",m:"Faltan 40 días para estar en casa. No para visitar: para VIVIR. Para que las calles que leen se conviertan en el camino al supermercado. Para que la lluvia sea normal y el sol sea celebración. 40 días."},
{d:"2026-08-23",e:"🧙",t:"Dumbledore es una palabra real en inglés",m:"'Dumbledore' es una palabra del inglés antiguo que significa 'abejorro'. Rowling eligió el nombre porque se imaginaba a Dumbledore tarareando para sí mismo mientras caminaba por los pasillos de Hogwarts. Un mago legendario con nombre de bicho que zumba. El humor sutil de Rowling es profundamente británico."},
{d:"2026-08-24",e:"🌧️",t:"Septiembre en Londres es el segundo verano",m:"Los londinenses llaman a septiembre 'second summer' porque a menudo tiene días más cálidos y soleados que agosto. Es cuando los parques se vacían de turistas y los londinenses los recuperan. Si tienen suerte, van a llegar a los últimos días de sol antes del otoño."},
{d:"2026-08-25",e:"🏙️",t:"Hyde Park albergó el primer edificio prefabricado del mundo",m:"El Crystal Palace, construido para la Gran Exposición de 1851, fue el primer edificio prefabricado de hierro y vidrio. Estaba en Hyde Park, al lado de donde van a vivir. Fue tan revolucionario que cambió la arquitectura para siempre. Se desarmó y se mudó a Sydenham, donde se incendió en 1936. Solo quedan los dinosaurios de Crystal Palace Park."},
{d:"2026-08-26",e:"👻",t:"Los muertos de la peste negra están debajo de Charterhouse Square",m:"Charterhouse Square en Clerkenwell es una plaza elegante con departamentos de lujo y un monasterio convertido en escuela. Debajo hay una fosa con aproximadamente 50.000 víctimas de la Peste Negra de 1348. La plaza tiene jardines cuidados. Todo sobre una ciudad de muertos. Londres no entierra su pasado: construye encima."},
{d:"2026-08-27",e:"🏙️",t:"Knightsbridge tiene los Horse Guards",m:"Los Horse Guards de la Reina están estacionados en Hyde Park Barracks en Knightsbridge, diseñado por Sir Basil Spence. Todos los días, los guardias a caballo pasan por su barrio camino al cambio de guardia. Van a desayunar con el sonido de caballos pasando por la ventana. No es una metáfora."},
{d:"2026-08-28",e:"🌸",t:"Regent's Park tiene un teatro al aire libre",m:"El Open Air Theatre de Regent's Park hace Shakespeare y musicales en verano. Mantas, vino, picnic, funciones que empiezan con sol y terminan con estrellas. Francine: está en tu campus. Lucca: es la cita perfecta. Para los dos: es el tipo de cosa que van a hacer y recordar siempre."},
{d:"2026-08-29",e:"🧙",t:"El espejo de Oesed muestra lo que más deseás",m:"'Oesed' es 'Deseo' escrito al revés. El espejo muestra el deseo más profundo de quien mira. Rowling dijo que Dumbledore ve calcetines de lana, pero en realidad ve a su familia reunida. Si ustedes miraran el espejo hoy, probablemente verían Knightsbridge, los parques, la lluvia, y a ustedes dos juntos ahí. Faltan 63 días."},
{d:"2026-08-30",e:"👻",t:"Jack the Ripper podría haber sido cirujano",m:"Una de las teorías más persistentes sobre Jack the Ripper es que era un cirujano o alguien con conocimientos médicos avanzados. Los cortes en las víctimas mostraban precisión anatómica. Francine: alguien con tus conocimientos podría haber hecho eso. La historia oscura de la medicina y la historia oscura de Londres se cruzan en Whitechapel."},
{d:"2026-08-31",e:"🏙️",t:"Mañana empieza septiembre",m:"El último mes completo antes de la mudanza. Septiembre en Londres es transición: el verano se despide, las hojas empiezan a cambiar, los pubs encienden las chimeneas por primera vez. La ciudad se prepara para recibirlos."},
{d:"2026-09-01",e:"🌧️",t:"El olor de Londres en otoño",m:"Hojas mojadas, café caliente, chimenea lejana, asfalto después de la lluvia, castañas asándose en puestos callejeros. El otoño londinense tiene un olor específico que no existe en ningún otro lugar del mundo. Cuando lo huelan por primera vez, van a saber que llegaron."},
{d:"2026-09-02",e:"👻",t:"The London Stone puede ser el corazón de la ciudad",m:"Hay una piedra antigua llamada London Stone, protegida detrás de una reja en Cannon Street. Nadie sabe exactamente qué es. Algunos dicen que es el punto desde el cual los romanos medían las distancias. Otros que es mística. La leyenda dice que mientras la piedra exista, Londres existirá. Está ahí desde hace más de 1000 años."},
{d:"2026-09-03",e:"🧙",t:"El 1° de septiembre el tren salió de King's Cross",m:"Ayer, a las 11am, King's Cross anunció la partida del Hogwarts Express. Si estuvieron cerca, lo escucharon. Si no, bríndense con algo. Cada 1° de septiembre, la frontera entre ficción y realidad se disuelve en una estación de tren. Están a 60 días de vivir en la ciudad donde eso pasa."},
{d:"2026-09-04",e:"🏙️",t:"Los londinenses caminan más rápido que cualquier ciudad europea",m:"Un estudio midió la velocidad promedio de los peatones en 32 ciudades. Londres fue la más rápida de Europa. El londinense promedio camina a 5.4 km/h. Los que van al trabajo en la City, más rápido. Van a notar que la gente camina con propósito. Adaptarse a ese ritmo toma unas semanas."},
{d:"2026-09-05",e:"🌸",t:"Open House London abre edificios secretos",m:"Este fin de semana (o el próximo), Open House London abre al público gratis edificios normalmente cerrados: casas privadas, estudios de arquitectos, estaciones de bombeo victorianas, bunkers. Es ver Londres como nunca. Lucca: hay data centres y oficinas tech incluidas."},
{d:"2026-09-06",e:"👻",t:"Debajo de la National Gallery hay una caverna medieval",m:"Cuando excavaron para construir la ampliación de la National Gallery encontraron una caverna medieval que nadie sabía que existía. Londres tiene más debajo de sus pies de lo que puede mapear. Cada obra de construcción descubre algo nuevo. La ciudad se excava a sí misma constantemente."},
{d:"2026-09-07",e:"🏙️",t:"50 días",m:"Cincuenta días para que esto deje de ser una app y empiece a ser la vida real. Para que la lluvia que leen se convierta en lluvia que sienten. Para que el queso que imaginan se convierta en queso que prueban. Para que Londres deje de ser un sueño y se convierta en la dirección de su casa."},
{d:"2026-09-08",e:"🧙",t:"Los libros de Harry Potter se traducen al latín y al griego antiguo",m:"Harrius Potter et Philosophi Lapis es la traducción al latín de La Piedra Filosofal. Es uno de los libros en latín más vendidos de la historia moderna. También existe en griego antiguo. Una saga para niños se convirtió en texto académico. Eso solo pasa con Shakespeare y con Rowling."},
{d:"2026-09-09",e:"🌧️",t:"Las ventanas de su casa van a tener gotas",m:"Va a haber mañanas donde se despierten y las ventanas de Knightsbridge estén cubiertas de gotas. Afuera, los árboles de Kensington Gardens van a estar grises y brillantes. Van a hacer café, van a mirar las gotas, y van a sentir algo que es difícil de nombrar pero que se parece mucho a estar exactamente donde quieren estar."},
{d:"2026-09-10",e:"🏙️",t:"Los mercados de comida son la vida social de Londres",m:"En Argentina, la vida social pasa en la casa. En Londres, pasa en el market. Broadway Market (sábados), Maltby Street (sábados), Columbia Road (domingos). Ir al market no es hacer las compras: es ver a los vecinos, probar cosas nuevas, sentirse parte de algo. Es donde se construye comunidad."},
{d:"2026-09-11",e:"👻",t:"La Torre de Londres tiene cuervos con nombres y un suplente",m:"Los 7 cuervos de la Torre se llaman Jubilee, Harris, Gripp, Rocky, Erin, Poppy y Merlina. Tienen las alas recortadas para que no se vayan. La leyenda dice que si los cuervos dejan la Torre, la monarquía cae. Tienen un cuervo extra 'de repuesto'. La burocracia británica aplicada a la superstición."},
{d:"2026-09-12",e:"🌸",t:"Los parques cambian de color esta semana",m:"A mediados de septiembre, Kensington Gardens empieza a cambiar. Las hojas más altas se vuelven amarillas primero. Para cuando lleguen en octubre, van a estar en pleno otoño dorado. Es la versión más fotogénica de su nuevo barrio."},
{d:"2026-09-13",e:"🏙️",t:"40 días",m:"Cuarenta días. Eso es lo que queda entre hoy y la vida que están construyendo. Cada dato que leyeron en esta app va a cobrar cuerpo. Los olores van a ser reales. Los sonidos van a tener volumen. Las calles van a tener textura bajo sus pies."},
{d:"2026-09-14",e:"🧙",t:"Rowling vivió en un departamento sin calefacción mientras escribía",m:"Cuando Rowling escribía La Piedra Filosofal en Edimburgo, vivía en un departamento tan frío que escribía en cafés para calentarse. El Elephant House y The Spoon (antes Nicolson's Café) fueron sus oficinas involuntarias. Hoy esos cafés son lugares de peregrinación. La pobreza de una escritora creó santuarios para millones."},
{d:"2026-09-15",e:"👻",t:"El Támesis tiene su propia policía desde 1798",m:"La Thames River Police es la fuerza policial más antigua del mundo (antes que Scotland Yard). Patrullan 54 millas de río. Recuperan cuerpos, investigan robos en embarcaciones y controlan tráfico fluvial. El río tiene su propia ley. Tiene su propia justicia."},
{d:"2026-09-16",e:"🌧️",t:"30 días",m:"Treinta días. Un mes. El último mes sin ser londinenses. A partir de ahora, cada dato que lean en esta app es algo que van a poder verificar en persona muy pronto. La cuenta regresiva ya se siente real."},
{d:"2026-09-17",e:"🏙️",t:"Los pubs cierran a las 11 pero los 'lock-ins' existen",m:"A las 11pm, el publican cierra la puerta. Técnicamente, todos se fueron. Pero a veces, la puerta se cierra con gente adentro. Eso es un 'lock-in': el pub sigue sirviendo en secreto. No es legal. Es tradición. Es una de las cosas más británicas que existen."},
{d:"2026-09-18",e:"🧙",t:"El Sorting Hat tardó más de un año en ser diseñado",m:"El equipo de producción de las películas creó más de 40 versiones del Sombrero Seleccionador antes de llegar al diseño final. Cada versión tenía diferentes 'expresiones faciales' en los pliegues del cuero. El sombrero final fue animado digitalmente pero el objeto físico existe y está en el Studio Tour."},
{d:"2026-09-19",e:"👻",t:"Londres tiene más de 170 museos",m:"Más de 170. La mayoría gratuitos. Es la mayor concentración de museos del mundo. Y lo más increíble: los británicos decidieron que la cultura debía ser gratuita. El British Museum, la National Gallery, Tate Modern, el V&A (que está al lado de su casa): todos gratis. Esa decisión dice algo profundo sobre la ciudad que eligieron."},
{d:"2026-09-20",e:"🌸",t:"20 días",m:"Veinte días. Pueden contarlos con los dedos de las manos y los pies. Cada amanecer es un día menos de espera y un día más cerca del principio de todo."},
{d:"2026-09-21",e:"🏙️",t:"La City de Londres tiene su propio gobierno medieval",m:"La City of London (la milla cuadrada del centro financiero) tiene su propio Lord Mayor, su propia policía, y leyes que datan de la Edad Media. Es técnicamente una entidad separada de Greater London. El Lord Mayor viaja en una carroza dorada una vez al año. Es un anacronismo que funciona."},
{d:"2026-09-22",e:"🌧️",t:"Las primeras chimeneas del otoño",m:"En septiembre, los pubs empiezan a encender las chimeneas. El olor a leña se mezcla con el aire frío y la humedad. Es la señal de que el otoño llegó de verdad. Cuando entren a un pub con chimenea encendida por primera vez, van a entender por qué los londinenses aman el invierno."},
{d:"2026-09-23",e:"🧙",t:"El Hogwarts Express es un tren real que se puede tomar",m:"Ya se los dije, pero vale repetirlo ahora que están más cerca: el Jacobite Steam Train, Fort William a Mallaig en Escocia. Cruza el viaducto de Glenfinnan. Vapor real, paisaje real, magia real. Es una excursión de fin de semana largo desde Londres. Pónganlo en la lista."},
{d:"2026-09-24",e:"👻",t:"15 días",m:"Quince días. Dos semanas. El tiempo que tarda un queso en madurar, una herida en cicatrizar, una persona en empezar a extrañar. En 15 días no van a extrañar nada porque van a estar exactamente donde quieren estar."},
{d:"2026-09-25",e:"🏙️",t:"Los parques de Londres cierran de noche con llave",m:"A diferencia de muchos parques del mundo, los Royal Parks de Londres cierran de noche. Hay horarios específicos que cambian con las estaciones. Los guardias literalmente cierran las rejas con llave. Es una tradición que viene de cuando los parques eran propiedad real y los ciervos necesitaban protección. Kensington Gardens cierra al atardecer."},
{d:"2026-09-26",e:"🌸",t:"10 días",m:"Diez días. Pueden contarlos con una mano dos veces. Cada dato que leyeron desde marzo va a tener dirección, olor y temperatura. En 10 días, Londres deja de ser información y se convierte en experiencia."},
{d:"2026-09-27",e:"🧙",t:"7 días",m:"Una semana. Siete amaneceres. Siete atardeceres. La próxima vez que cuenten hasta siete, van a estar en Londres. Van a estar en casa."},
{d:"2026-09-28",e:"🌧️",t:"El primer café que tomen en Londres",m:"Va a haber un momento, probablemente al día siguiente de llegar, donde van a sentarse en un café de Knightsbridge con un flat white. Afuera va a estar gris, o lloviendo, o soleado. No importa. Van a mirar la calle y van a pensar: 'vivimos acá'. Ese café va a ser el mejor que tomen en su vida."},
{d:"2026-09-29",e:"🏙️",t:"3 días",m:"Tres días. 72 horas. La distancia entre hoy y el resto de sus vidas en Londres. Respiren. Ya llegan."},
{d:"2026-09-30",e:"👻",t:"Mañana empieza octubre",m:"El último mes. El mes donde todo cambia. Donde la pantalla se convierte en ventana. Donde el dato se convierte en dirección. Donde la imaginación se convierte en realidad. Octubre. Su mes. Su ciudad. Su vida."},
{d:"2026-10-01",e:"🏙️",t:"31 días",m:"Un mes para que esta app se vuelva innecesaria. Para que dejen de leer sobre Londres y empiecen a vivir Londres. Para que los datos se conviertan en experiencia y las palabras en recuerdos. 31 días."},
{d:"2026-10-02",e:"🌧️",t:"Cuando llueva por primera vez en Knightsbridge",m:"Va a pasar pronto después de llegar. Van a estar caminando por Brompton Road y va a empezar a llover. No torrencial: llovizna. El tipo de lluvia que no justifica paraguas. Van a seguir caminando. Y en ese momento, en esa llovizna, van a ser londinenses."},
{d:"2026-10-03",e:"🌸",t:"Los árboles de Kensington Gardens en octubre",m:"Los plátanos de la avenida principal se ponen dorados. Los robles se oscurecen. Las hojas crujen bajo los pies. La bruma matutina hace que el parque parezca un cuadro de Turner. Todo esto está a 3 minutos de su puerta."},
{d:"2026-10-04",e:"🧙",t:"El Studio Tour decora para Halloween",m:"En octubre, el Warner Bros Studio Tour se viste de Halloween. El Gran Comedor se prepara para el banquete de Halloween como en las películas. Calabazas flotantes, murciélagos, telarañas. Si van este mes, van a ver Hogwarts en su versión más oscura. Reserven ya."},
{d:"2026-10-05",e:"👻",t:"La Torre de Londres en Halloween",m:"Calabazas iluminadas entre murallas de 1000 años. Los Beefeaters hacen tours nocturnos con historias reales de ejecuciones, traiciones y fantasmas. Los cuervos observan desde las torres con sus ojos negros. Si un lugar nació para Halloween, es este."},
{d:"2026-10-06",e:"🏙️",t:"Harrods está a 5 minutos de casa",m:"No como dato turístico: como realidad cotidiana. La Food Hall, los quesos, la charcutería, la pastelería francesa. Todo a 5 minutos caminando. Van a ir a comprar leche y van a terminar con un queso que no planeaban comprar. Muchas veces."},
{d:"2026-10-07",e:"🌧️",t:"Bonfire Night se acerca",m:"El 5 de noviembre hay fuegos artificiales por todo Londres. Se celebra que Guy Fawkes FALLÓ en volar el Parlamento. Queman muñecos de él. Es la celebración más extraña del calendario británico: festejar un fracaso. Y es hermosa."},
{d:"2026-10-08",e:"🏙️",t:"Caminen por Knightsbridge de noche",m:"Su barrio de noche es diferente. Las luces de Harrods iluminan Brompton Road. Los Horse Guards Barracks están en silencio. Hyde Park está cerrado y oscuro detrás de las rejas. Es elegante, es quieto, y es su casa."},
{d:"2026-10-09",e:"🧙",t:"Vayan a Leadenhall Market un martes a las 4pm",m:"Cuando la luz de otoño se filtra por los vidrios victorianos del Callejón Diagon real, el mercado parece exactamente como en las películas. Los banqueros pasan sin notar que están caminando por un set de cine. Quédense hasta que prendan las luces."},
{d:"2026-10-10",e:"🌸",t:"Su primer amanecer en Kensington Gardens",m:"Alguna mañana temprano, vayan al parque antes de que llegue nadie. La bruma matutina, los pájaros, los ciervos de la zona norte, los periquitos verdes. Todo eso es suyo ahora. Todos los días. Sin entrada. Sin reserva. Sin fin."},
{d:"2026-10-11",e:"👻",t:"La primera noche que escuchen un zorro gritar",m:"Los zorros de Londres gritan de noche. Suena como un humano aterrorizado. La primera vez que lo escuchen van a pensar que alguien está en peligro. Es solo un zorro. Son vecinos. Se van a acostumbrar. Pero la primera vez es inolvidable."},
{d:"2026-10-12",e:"🏙️",t:"Su primera semana como londinenses",m:"Para este punto ya van a haber descubierto su café, su camino al supermercado, su ruta por el parque. Las calles van a tener nombres que reconocen. Los sonidos van a ser familiares. Londres ya no es un lugar al que vinieron. Es el lugar donde viven."},
{d:"2026-10-13",e:"🩺",t:"Francine empieza en Regent's",m:"Caminando al aula por Regent's Park. 410 acres de jardines, un lago, rosedales. El campus más lindo del planeta. La neurocirugía nunca estuvo más cerca de la naturaleza. Hoy empieza tu capítulo, Francine."},
{d:"2026-10-14",e:"🌧️",t:"Su primer día gris en casa",m:"Va a haber un día gris, lluvioso, donde estén en su casa mirando por la ventana. Kensington Gardens goteando, cielo plomo, lluvia contra los vidrios. Y van a sonreír. Porque es exactamente lo que eligieron. Es exactamente lo que querían."},
{d:"2026-10-15",e:"🧙",t:"Vayan al Palace Theatre de noche",m:"Pasen por la fachada de Harry Potter and the Cursed Child en Charing Cross Road de noche. No necesitan entrar. Las letras doradas brillan sobre la calle como magia real. Cuando estén listos, compren entradas. No hay apuro. La magia los espera."},
{d:"2026-10-16",e:"🏙️",t:"Busquen su pub",m:"Es un rito de pasaje. El lugar donde el bartender les sirve 'lo de siempre' sin preguntar. Donde la mesa del rincón es 'su' mesa. Puede tomar semanas. No se apuren. El pub correcto los va a encontrar a ustedes."},
{d:"2026-10-17",e:"🌸",t:"Lleven una botella de vino al parque",m:"No hace falta un plan elaborado. Solo una botella, dos copas (o una, compartida), y un banco en Kensington Gardens con vista a los árboles dorados. Es gratuito, es simple, y es el tipo de momento que define una vida juntos en una ciudad nueva."},
{d:"2026-10-18",e:"👻",t:"Los ghost tours son diferentes cuando vivís acá",m:"Cuando sos turista, un ghost tour es entretenimiento. Cuando vivís en Londres, es historia de TU ciudad. Jack the Ripper caminó por TUS calles. Los fantasmas están en TUS estaciones de Tube. Es tu historia oscura ahora."},
{d:"2026-10-19",e:"🏙️",t:"Caminen sin Google Maps",m:"Un día, apaguen el GPS. Piérdanse. Londres recompensa a los que se pierden: callejones georgianos, jardines escondidos, pubs sin nombre. Las mejores cosas de esta ciudad no se googlean. Se encuentran doblando donde no pensaban doblar."},
{d:"2026-10-20",e:"🌧️",t:"Cuando llueva, vayan a un bookshop",m:"Charing Cross Road, Cecil Court, Daunt Books en Marylebone. Las librerías de Londres bajo la lluvia son refugios perfectos. El olor a libros viejos mezclado con el sonido de la lluvia contra las ventanas. Es un abrazo arquitectónico."},
{d:"2026-10-21",e:"🧙",t:"Hogwarts es un estado mental",m:"Rowling dijo que Hogwarts es 'the safest place in the world'. No es un castillo: es la idea de un lugar donde pertenecés. Donde te aceptan como sos. Donde la magia es posible. Londres puede ser eso. Ya es eso. Para ustedes, ahora."},
{d:"2026-10-22",e:"🏙️",t:"Su primer Sunday roast",m:"Carne asada, Yorkshire pudding, roast potatoes, gravy. En un pub con chimenea. Un domingo lluvioso de otoño. La tradición más sagrada del calendario gastronómico británico. Cuando lo prueben, van a entender por qué los ingleses aguantan todo lo demás."},
{d:"2026-10-23",e:"🌸",t:"Los cherry blossoms van a volver en primavera",m:"En marzo-abril de 2027, los mismos árboles que ahora están dorados van a cubrirse de flores blancas y rosadas. Kensington Gardens se va a transformar. Van a vivir eso. Van a ver el ciclo completo. El primer año es el más revelador."},
{d:"2026-10-24",e:"🏙️",t:"Abran una botella de vino en casa",m:"Rodeados de cajas o ya instalados. No importa. Abran una botella. No tiene que ser cara. Tiene que ser la primera. Brinden por el viaje, por lo que dejaron, por lo que encontraron. Londres empieza con un brindis entre ustedes dos."},
{d:"2026-10-25",e:"🌧️",t:"El primer invierno viene",m:"Noviembre es gris, húmedo, oscuro a las 4pm. Pero también: chimeneas en pubs, chocolate caliente, la preparación para la Navidad más cinematográfica del mundo. Mercados navideños, luces de Oxford Street, patinaje en el Natural History Museum (que está al lado de casa). Su próximo capítulo."},
{d:"2026-10-26",e:"👻",t:"La ciudad oscura y la ciudad clara",m:"Londres tiene dos versiones: la postal y la subterránea. Big Ben y los fantasmas. Buckingham y las fosas. El Támesis dorado y los cuerpos que arrastra. Ustedes que aman las dos van a vivir en una ciudad que satisface ambas curiosidades."},
{d:"2026-10-27",e:"🧙",t:"La magia es real en una ciudad así",m:"Lo suficientemente vieja para tener fantasmas, lo suficientemente nueva para tener futuro, lo suficientemente grande para que siempre haya algo que no conocen. La magia de Harry Potter nació en una ciudad donde lo imposible se siente posible. Esa ciudad ahora es suya."},
{d:"2026-10-28",e:"🌸",t:"Creen su playlist de Londres",m:"The Clash, The Kinks, Amy Winehouse, Burial, Lily Allen, The Streets. Armen la suya. Agréguenle canciones a medida que descubran la ciudad. Va a ser el soundtrack de esta etapa. Cada canción les va a recordar una calle."},
{d:"2026-10-29",e:"🏙️",t:"La moda londinense es ser vos mismo",m:"Punk en el Tube, traje de tres piezas en Brick Lane, vintage de los 40 en Peckham. La regla de la moda londinense es que no hay regla. La ropa no clasifica: expresa. Vístanse como quieran. Nadie los va a juzgar."},
{d:"2026-10-30",e:"🌧️",t:"Mañana",m:"Mañana se termina esta cuenta regresiva y empieza la otra: la de los días VIVIDOS en Londres. Cada dato que leyeron va a cobrar forma real. Las calles van a tener olor. Los sonidos van a tener volumen. La ciudad los recibe como recibe a todos: con lluvia, con historia y con los brazos abiertos."},
{d:"2026-10-31",e:"✨",t:"Welcome home",m:"Lucca y Francine: ya no son turistas. Son londinenses. Con su amor por el vino y el queso, su curiosidad por la historia oscura, su pasión por la música y la moda, y las ganas de vivirlo todo juntos. Londres no es una ciudad: son 32 ciudades disfrazadas de una sola. Tienen toda una vida para descubrirlas. Bienvenidos a casa. 🇦🇷 → 🇬🇧"},
];

const M = [
{w:1,t:"Misión #1",h:"Hay un lugar donde el vino más viejo de Londres se bebe a la luz de las velas, debajo de la calle. Encuéntrenlo.",l:"47 Villiers St, WC2N 6NE",time:"Cualquier tarde después de las 5pm",tips:"Vayan sin reserva. Busquen la entrada del sótano. Pidan sherry del barril y una tabla de quesos. Siéntense lo más adentro posible."},
{w:2,t:"Misión #2",h:"Busquen la callejuela de Covent Garden donde parece que el tiempo se detuvo en 1750. Bow windows, faroles, nadie alrededor.",l:"Goodwin's Court, WC2N 4LL",time:"De noche, después de las 8pm",tips:"Entren por Bedfordbury. Está entre St Martin's Lane y Bedfordbury. No hay cartel. Si ven bow windows georgianas iluminadas por faroles, llegaron."},
{w:3,t:"Misión #3",h:"A 10 minutos de casa hay un jardín escondido dentro de un museo que parece una selva tropical. Solo abre algunos domingos.",l:"Barbican Conservatory, Silk St, EC2Y 8DS",time:"Domingos (verificar web)",tips:"Es gratis pero hay que reservar online. Es el segundo invernadero más grande de Londres, escondido dentro del brutalismo del Barbican."},
{w:4,t:"Misión #4",h:"Hay un cementerio victoriano donde la naturaleza se comió las tumbas y una capilla está en ruinas. Tiene la mejor vista secreta de St Paul's.",l:"Nunhead Cemetery, Linden Grove, SE15 3LP",time:"Sábados por la mañana",tips:"Entren por la puerta principal, caminen hasta el fondo, busquen el claro entre los árboles con vista a la ciudad. Lleven café."},
{w:5,t:"Misión #5",h:"Suban al techo de un edificio que parece una catedral de hormigón. Hay un jardín secreto allá arriba con plantas tropicales y vista de toda la ciudad.",l:"Sky Garden, 20 Fenchurch St, EC3M 3BY",time:"Reservar gratis online, preferiblemente atardecer",tips:"Vayan al atardecer. El bar del techo tiene cócteles. La vista de Tower Bridge iluminada es increíble."},
{w:6,t:"Misión #6",h:"Encuentren la tienda donde el reloj gira al revés. Está en una calle que cambió la moda para siempre.",l:"430 King's Road, Chelsea, SW10 0LJ",time:"Horario de tienda",tips:"La tienda es World's End de Vivienne Westwood. Miren hacia arriba: el reloj gigante gira en sentido contrario desde 1971."},
{w:7,t:"Misión #7",h:"Bajo un arco del tren, hay un lugar donde derriten queso suizo frente a tus ojos sobre papas y pickles. Coman parados bajo la lluvia.",l:"Kappacasein, Borough Market, SE1 1TL",time:"Sábados por la mañana, antes de las 11",tips:"La cola es larga. Vale la pena. Pidan la raclette original. Coman parados en la calle."},
{w:8,t:"Misión #8",h:"Caminen por el canal desde Little Venice hasta Camden. Son 3km. Hay botes pintados, patos y pubs junto al agua. Paren en un pub a mitad de camino.",l:"Little Venice, Warwick Ave, W9",time:"Domingo por la mañana",tips:"Empiecen en Warwick Avenue Station. Caminen hacia el este por el towpath de Regent's Canal. The Waterside Café está a mitad de camino."},
{w:9,t:"Misión #9",h:"Hay una casa donde si entrás en silencio podés sentir que alguien acaba de irse de cada habitación. Velas encendidas, comida en la mesa.",l:"Dennis Severs' House, 18 Folgate St, E1 6BX",time:"Lunes por la noche (Silent Night visits)",tips:"Reserven las 'Silent Night' visits. Son con velas. No hablen. No toquen nada. Solo sientan. Es la experiencia más única de Londres."},
{w:10,t:"Misión #10",h:"Busquen un pub tan escondido en un callejón de Belgravia que los turistas nunca lo encuentran. Tiene un fantasma y los mejores Bloody Mary.",l:"The Grenadier, 18 Wilton Row, SW1X 7NR",time:"Domingo al mediodía",tips:"Está escondido en un callejón detrás de un arco. Busquen 'Wilton Row'. El Bloody Mary del Grenadier es legendario. Están a 10 min caminando de casa."},
{w:11,t:"Misión #11",h:"En el ático de una iglesia hay un quirófano de 200 años. Francine: vas a ver lo que era la cirugía antes de la anestesia.",l:"Old Operating Theatre, 9a St Thomas St, SE1 9RY",time:"Cualquier día, verificar horarios",tips:"Suban por la escalera de caracol. Es estrecho. El aserrín en el piso era para la sangre. Los instrumentos son reales."},
{w:12,t:"Misión #12",h:"Hay un mercado de antigüedades que abre a las 5am los viernes. Vayan con linterna. Los dealers serios ya están ahí.",l:"Bermondsey Square, SE1 3UN",time:"Viernes, 5am",tips:"Madrugar es obligatorio. Lleven efectivo. Las mejores piezas se van antes del amanecer. Después: desayuno inglés completo en cualquier café de Bermondsey."},
{w:13,t:"Misión #13",h:"Busquen el bar escondido arriba de un pub en Chinatown. Tiene nombre de personaje de cine noir y banquetas azul medianoche.",l:"The Mulwray, Blue Posts, 28 Rupert St, W1D 6DJ",time:"Jueves o viernes noche",tips:"Entren al pub Blue Posts, suban las escaleras. Pidan un vino natural de la sección 'The Path Less Trodden'. El contraste con Chinatown abajo es perfecto."},
{w:14,t:"Misión #14",h:"Hay un deli de Mayfair con un wine bar secreto en el sótano. Sin cartel. Solo flechas adentro.",l:"Farm Shop, 63 South Audley St, W1K 2QH",time:"Después de las 5pm",tips:"Entren como si fueran a comprar queso. Busquen las flechas que llevan escaleras abajo. Pidan cheese toasties y un vino blanco de la carta. Están a 10 min de casa."},
{w:15,t:"Misión #15",h:"Crucen el puente que 'wobbleó' y que los mortífagos destruyeron. Empiecen en St Paul's, terminen en Tate Modern.",l:"Millennium Bridge, EC4V 4QE",time:"Atardecer",tips:"Crucen lento. Miren el Támesis. Recuerden que se movía cuando abrió en 2000. Recuerden que se destruyó en El Príncipe Mestizo. Hoy es sólido, como ustedes acá."},
{w:16,t:"Misión #16",h:"Hay un parque en el sur de Londres con dinosaurios victorianos de 1854. Están en una isla y son históricamente incorrectos de formas encantadoras.",l:"Crystal Palace Park, Thicket Rd, SE20 8DT",time:"Sábado por la mañana",tips:"Busquen la isla de los dinosaurios. Son las primeras esculturas de dinosaurios del mundo. Son inexactas y maravillosas. El parque es enorme."},
{w:17,t:"Misión #17",h:"Vayan al mercado de flores de Columbia Road un domingo. Al lado hay una tienda de quesos donde un chef obsesivo selecciona 30 quesos británicos.",l:"Columbia Road & Funk Cheese, E2 7RG",time:"Domingo, 8am-2pm",tips:"Compren flores para la casa. Después entren a Funk. Pidan un cheese board armado y un vino natural para llevar. Creen su ritual de domingo."},
{w:18,t:"Misión #18",h:"Busquen la placa diminuta en el piso cerca de Marble Arch. Marca donde 50.000 personas fueron ejecutadas durante 600 años.",l:"Intersection of Edgware Rd & Bayswater Rd, W2",time:"Cualquier día",tips:"La placa es fácil de perder. Está en la isla de tráfico. 50.000 personas murieron en el cadalso de Tyburn. Hoy pasan autos."},
{w:19,t:"Misión #19",h:"Hay un afternoon tea donde los pasteles replican piezas de las colecciones de moda actuales. Está en su barrio.",l:"The Berkeley, Wilton Place, SW1X 7RL",time:"Reservar con anticipación",tips:"Se llama Prêt-à-Portea. Los pasteles cambian cada temporada de moda. Está a minutos caminando de casa. Vayan de tarde, bien vestidos."},
{w:20,t:"Misión #20",h:"Encuentren el pub más viejo que puedan. Tiene que tener al menos 300 años. Tómense una pinta donde probablemente Dickens se emborrachó.",l:"Ye Olde Cheshire Cheese, 145 Fleet St, EC4A 2BU",time:"Cualquier tarde",tips:"Bajen al sótano. Los ladrillos son del siglo XVII. El pub sobrevivió al Gran Incendio. Samuel Johnson, Dickens y Mark Twain tomaron acá."},
{w:21,t:"Misión #21",h:"Caminen por Hampstead Heath hasta Parliament Hill. Lleven un thermos con café. La vista del skyline al amanecer es la mejor de Londres.",l:"Hampstead Heath, Parliament Hill, NW5",time:"Amanecer",tips:"Sí, hay que madrugar. La bruma matutina sobre la ciudad es irreal. Lleven mantas si hace frío. Es el tipo de momento que recuerdan para siempre."},
{w:22,t:"Misión #22",h:"Hay una calle en el East End donde Jack the Ripper caminó. El pub donde sus víctimas tomaron su último trago sigue abierto. Vayan de noche.",l:"Ten Bells, 84 Commercial St, E1 6LY",time:"Viernes por la noche",tips:"No hagan tour organizado. Vayan solos. Caminen Whitechapel después. Las calles cambiaron pero la traza es la misma. La oscuridad ayuda."},
{w:23,t:"Misión #23",h:"Busquen un puesto en Borough Market donde cortan jamón ibérico a mano. Cómprense 100g y cómanlo ahí mismo con pan.",l:"Brindisa, Borough Market, SE1 9AB",time:"Sábado temprano",tips:"Brindisa. Pidan 100g de jamón cortado a mano. Un pedazo de Manchego. Pan. Páguenlo todo y cómanlo parados en el mercado. Eso es felicidad."},
{w:24,t:"Misión #24",h:"Hay un hotel donde las habitaciones parecen Hogwarts. No tienen que quedarse: solo vayan al lobby y vean las Wizard Chambers.",l:"Georgian House Hotel, 35-39 St George's Dr, SW1V 4DG",time:"Cualquier día",tips:"No necesitan ser huéspedes. Pregunten amablemente si pueden ver las Wizard Chambers. A veces dejan espiar. Si no, el lobby ya tiene vibra mágica."},
{w:25,t:"Misión #25",h:"Busquen el edificio de Londres hecho con maderas de barcos de guerra. Adentro hay una escalera que parece de otra época.",l:"Liberty, Great Marlborough St, W1B 5AH",time:"Cualquier día",tips:"Entren por la puerta principal. Suban por la escalera de madera oscura. El edificio entero fue construido con madera de HMS Impregnable y HMS Hindustan."},
{w:26,t:"Misión #26",h:"Hay un parque en Stoke Newington que es cementerio, reserva natural y bosque gótico al mismo tiempo. Tiene una capilla en ruinas.",l:"Abney Park, Stoke Newington High St, N16 0LH",time:"Sábado por la mañana, con café",tips:"Entren por la puerta de Church Street. Caminen hasta la capilla. Las raíces de los árboles crecen entre las tumbas. Es hermoso de una forma que no debería ser hermoso."},
{w:27,t:"Misión #27",h:"Suban a la Glass Walkway de Tower Bridge. Es la única atracción turística importante que acepta perros (para cuando tengan uno).",l:"Tower Bridge, SE1 2UP",time:"Día claro, cualquier horario",tips:"42 metros sobre el Támesis, caminando sobre vidrio. Miren abajo cuando pase un barco. Si ya tienen perro, llévenlo."},
{w:28,t:"Misión #28",h:"Busquen una wine tasting donde les sirvan English sparkling wine. Prueben 3 y digan cuál es mejor que champagne.",l:"Berry Bros. & Rudd, 3 St James's St, SW1A 1EG",time:"Verificar eventos en su web",tips:"Berry Bros tiene tastings regularmente. Si no, busquen en Nyetimber Pop-Up (suelen tener uno en Selfridges). Debatan entre ustedes."},
{w:29,t:"Misión #29",h:"Hay un lugar en Bermondsey donde un affineur francés madura quesos en cuevas. Pídanle que les muestre la cueva.",l:"Mons Cheesemongers, Borough Market, SE1 1TL",time:"Sábado por la mañana",tips:"Pregunten por el proceso de affinage. Si están de humor, les muestran. Compren un Comté de 18+ meses y un Beaufort. Llévenlo a casa con pan y vino."},
{w:30,t:"Misión #30",h:"Caminen por Regent's Canal de King's Cross a Victoria Park. 5km sin autos, junto al agua. Paren en un pub del canal.",l:"King's Cross, N1C → Victoria Park, E9",time:"Domingo",tips:"Empiecen en Granary Square. Pasen por debajo de los puentes de Islington. Paren en The Narrowboat o The Proud Archivist. Terminen en Victoria Park con una pinta."},
{w:31,t:"Misión #31",h:"Hay un museo en Mile End que era una escuela para los niños más pobres del East End victoriano. Siéntense en los bancos de madera.",l:"Ragged School Museum, 46-50 Copperfield Rd, E3 4RR",time:"Miércoles o jueves, gratis",tips:"El aula recreada es conmovedora. Siéntense en los bancos. Usen las pizarras. Piensen en los niños que estudiaron ahí hace 150 años."},
{w:32,t:"Misión #32",h:"Busquen una tienda de vinos que funciona desde 1698. Napoleon III vivió arriba. Entren a la bodega si los dejan.",l:"Berry Bros. & Rudd, 3 St James's St, SW1A 1EG",time:"Cualquier día de semana",tips:"Pregunten si pueden ver la bodega histórica. A veces dan mini tours. Compren una botella de algo especial para una ocasión futura."},
{w:33,t:"Misión #33",h:"Vayan al Proms. Compren Promenade tickets el mismo día. £8 por estar parados en el arena del Royal Albert Hall.",l:"Royal Albert Hall, Kensington Gore, SW7 2AP",time:"Cualquier noche de julio-septiembre",tips:"La cola para Proms empieza temprano pero vale la pena. Lleven algo para picar. La acústica parados en el arena es increíble."},
{w:34,t:"Misión #34",h:"Busquen un pub con chimenea encendida en un día lluvioso de invierno. Pidan una pinta y un Sunday roast. No se apuren en irse.",l:"Elijan uno cerca de casa o lejos",time:"Domingo lluvioso de invierno",tips:"El objetivo es encontrar SU pub de invierno. El que tiene la chimenea correcta, el roast correcto, la atmósfera correcta. Puede que necesiten varios intentos."},
{w:35,t:"Misión #35",h:"Hay un potion bar donde les dan varita y capa y preparan cocktails como pociones. Vayan sin ironía.",l:"The Cauldron, 157 Stoke Newington Rd, N16 8BU",time:"Reservar online, noche de viernes",tips:"2 horas, welcome drink + 2 cocktails que preparan ustedes. Es kitsch y glorioso. Tómenselo en serio. La magia funciona mejor sin ironía."},
{w:36,t:"Misión #36",h:"Busquen los cherry blossoms de primavera en Kensington Gardens. Su parque. Sus árboles. Su primera primavera londinense.",l:"Kensington Gardens, W2 2UH",time:"Finales de marzo / principios de abril",tips:"Los árboles blancos y rosa que aman están a 3 minutos de casa. Caminen por el lado este de los jardines. Sáquense una foto debajo. Es su ciudad ahora."},
{w:37,t:"Misión #37",h:"Hay un market de comida debajo de un puente de tren en Bermondsey que los londinenses prefieren sobre Borough. Más chico, menos turistas.",l:"Maltby Street Market, SE1 3PA",time:"Sábados, llegar antes de las 11",tips:"Busquen el puesto de grilled cheese y el de pasta fresca. Compren vino natural en una de las tiendas del arco. Coman sentados en el cordón."},
{w:38,t:"Misión #38",h:"Vayan a un partido de Dulwich Hamlet. Entradas a £12. Cerveza artesanal. Banderas de diseño. Fútbol comunitario real.",l:"Champion Hill, Edgar Kail Way, SE22 8BD",time:"Verificar fixtures online",tips:"Si ya tienen perro, llévenlo. Aceptan perros. Es fútbol de sexta división con más alma que muchos de primera."},
{w:39,t:"Misión #39",h:"Busquen la entrada secreta al Ministerio de Magia. Está en una calle gubernamental detrás de Whitehall.",l:"Scotland Place, SW1A 2HW",time:"Cualquier día",tips:"Es una calle corta y elegante. La cabina telefónica roja de la película ya no está (fue para el rodaje) pero el lugar tiene la misma energía de doble realidad."},
{w:40,t:"Misión #40",h:"Hay una conservatory tropical DENTRO del brutalismo del Barbican. Solo abre algunos domingos. Es gratis.",l:"Barbican Conservatory, Silk St, EC2Y 8DS",time:"Verificar domingos de apertura online",tips:"Reserven. Es el segundo invernadero más grande de Londres, escondido dentro del hormigón. El contraste es surrealista."},
{w:41,t:"Misión #41",h:"Caminen por el Thames Path desde Teddington Lock hasta Kingston Bridge. 3km junto al río. Terminen en un pub.",l:"Teddington Lock, TW11",time:"Sábado o domingo",tips:"The Boaters en Kingston tiene pintas con vista al Támesis. El camino es plano, verde y tranquilo. Si tienen perro, ideal."},
{w:42,t:"Misión #42",h:"Encuentren Crossbones Graveyard. Las cintas en las rejas. Los mensajes. Los 15.000 olvidados.",l:"Redcross Way, SE1 0HN",time:"Cualquier día, preferiblemente solo",tips:"Páren frente a las rejas. Lean los mensajes. Son de personas que vienen a recordar a las 15.000 personas sin nombre enterradas ahí. Es silencioso y poderoso."},
{w:43,t:"Misión #43",h:"Busquen un cheese room donde puedan entrar y estar rodeados de quesos en temperatura perfecta. Compren 3 que no conozcan.",l:"La Fromagerie, 2-6 Moxon St, W1U 4EW",time:"Cualquier día",tips:"Pidan entrar al cheese room. Está a la derecha de la tienda. Elijan un queso francés, uno británico y uno suizo que nunca hayan probado. Llévenlos a casa con pan."},
{w:44,t:"Misión #44",h:"Vayan a una jam session de jazz un lunes a la noche. Quédense hasta que se olviden qué hora es.",l:"Ronnie Scott's, 47 Frith St, W1D 4HT",time:"Lunes después de las 11pm",tips:"La Late Late Show de los lunes. £15. Siéntense en la barra del fondo. Pidan un whisky. Dejen que la música decida cuándo se van."},
{w:45,t:"Misión #45",h:"Hay un lugar en Richmond que es un vivero convertido en restaurante. Coman rodeados de plantas. Parece otro país.",l:"Petersham Nurseries, Church Lane, TW10 7AB",time:"Reservar para almuerzo",tips:"La luz filtrada por el vidrio del invernadero. Las plantas por todos lados. La comida es estacional y preciosa. Es lo más 'English country' sin salir de Londres."},
{w:46,t:"Misión #46",h:"Busquen la vista del skyline desde Parliament Hill al atardecer. Lleven vino y queso.",l:"Parliament Hill, Hampstead Heath, NW5",time:"Atardecer de un día claro",tips:"Suban hasta arriba. Abran el vino. Corten el queso. Miren la ciudad encenderse debajo. Brinden. Es su ciudad."},
{w:47,t:"Misión #47",h:"Hay 5 pisos de antigüedades en un edificio art deco en Marylebone. Piérdanse 2 horas. Compren algo que cuente una historia.",l:"Alfies Antique Market, 13-25 Church St, NW8 8DT",time:"Martes a sábado, 10-6pm",tips:"No busquen nada específico. Déjense llevar de piso en piso. Tomen un café en el rooftop al final. Lo que compren va a tener historia."},
{w:48,t:"Misión #48",h:"Vayan al V&A un viernes a la noche. Tienen 'Friday Late' events con música, charlas y cócteles. Es el museo más lindo de Londres. Está al lado de casa.",l:"V&A, Cromwell Rd, SW7 2RL",time:"Viernes, verificar eventos online",tips:"V&A Lates son gratuitos. Hay DJ, comida, charlas, performances. El museo se transforma de noche. Está literalmente al lado de Knightsbridge."},
{w:49,t:"Misión #49",h:"Busquen un lugar donde alquilen paddleboards en el Támesis. Remen juntos al atardecer.",l:"Active360, multiple locations",time:"Verificar en active360.co.uk, día cálido",tips:"Kew o Putney son los mejores puntos. Si ya tienen perro, puede ir en el paddleboard. No es broma."},
{w:50,t:"Misión #50",h:"Vayan a ver un partido de algún equipo en un estadio que tenga más de 100 años de historia.",l:"Selhurst Park, Crystal Palace o Craven Cottage, Fulham",time:"Verificar fixtures",tips:"La tribuna de un estadio viejo vibra diferente. El hormigón tiene historia. Los cantos tienen peso. Sientan eso al menos una vez."},
{w:51,t:"Misión #51",h:"Es casi un año. Vuelvan al primer lugar que visitaron cuando llegaron a Londres. Vean cómo cambió (la ciudad o ustedes).",l:"El primer lugar que visitaron",time:"Aniversario o cerca",tips:"Pidan lo mismo que pidieron la primera vez. Siéntense en el mismo lugar si pueden. Mídanse contra ese primer día. Van a verse diferentes."},
{w:52,t:"Misión #52",h:"Abran una botella de vino en su casa de Knightsbridge. Miren por la ventana. Los árboles de Kensington Gardens afuera. Un año vivido en Londres. Brinden por lo que viene.",l:"Su casa, Knightsbridge",time:"Fin de 2027",tips:"No necesitan ir a ningún lado. La misión final es quedarse. Estar juntos. En la ciudad que eligieron. En la vida que construyeron. Salud. 🇦🇷 → 🇬🇧"}
];


const CAT = {
  "🍷":"Wine","🧙":"Harry Potter","👻":"Historia Oscura","🏟️":"Sports",
  "☕":"Afternoon Tea","🧀":"Cheese & Food","👗":"Fashion & Vintage",
  "🎵":"Music & Arts","🏙️":"City Life",
  "🌧️":"Rainy Days","🌸":"Parks & Nature","🩺":"Medicine",
  "✨":"Welcome Home",
};

const END_COUNTDOWN = new Date(2026, 9, 31);
const td = () => { const n=new Date(); return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,"0")}-${String(n.getDate()).padStart(2,"0")}`; };
const parseDt = s => { const [y,m,d]=s.split("-").map(Number); return new Date(y,m-1,d); };
const fmtDate = s => parseDt(s).toLocaleDateString("es-AR",{weekday:"long",day:"numeric",month:"long"});
const daysTo = () => Math.max(0,Math.ceil((END_COUNTDOWN-new Date())/86400000));
const MN = {"03":"Marzo","04":"Abril","05":"Mayo","06":"Junio","07":"Julio","08":"Agosto","09":"Septiembre","10":"Octubre"};

const BG="#001C3D", BG2="#00122A", GOLD="#DC2626", SOFT="#94ADC7", TXT="#E8E1D3", MUT="#4A6278";
const CARD="rgba(255,255,255,0.04)", BRD="rgba(255,255,255,0.07)";
const S="'Libre Franklin',sans-serif", T="'Bodoni Moda',Georgia,serif";
const FONTS = "https://fonts.googleapis.com/css2?family=Bodoni+Moda:ital,opsz,wght@0,6..96,400;0,6..96,700;1,6..96,400&family=Libre+Franklin:wght@300;400;500;600&display=swap";

function Onboarding({onDone}) {
  const [step,setStep]=useState(0);
  const steps=[
    {icon:"🇬🇧",title:"Bienvenidos",sub:"220 datos sobre Londres\npersonalizados para ustedes.\nUno nuevo cada día."},
    {icon:"📱",title:"Guardar como App",sub:"Para tener esto siempre a mano:",detail:["1. Tocá el ícono  ⬆️  abajo en Safari","2. Scrolleá y elegí \"Agregar a Inicio\"","3. Confirmá con \"Agregar\""]},
    {icon:"🗝️",title:"Misiones secretas",sub:"Cuando lleguen a Londres,\nactiven el Modo Londres.\n52 misiones semanales\npara descubrir la ciudad."},
    {icon:"✨",title:"Listo",sub:"Cada día, un dato nuevo.\nCada semana en Londres, una misión.\nAbran cuando quieran."},
  ];
  const s=steps[step];
  return (
    <div style={{minHeight:"100vh",background:BG,color:TXT,fontFamily:T,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"40px 28px",textAlign:"center"}}>
      <link href={FONTS} rel="stylesheet"/>
      <div style={{fontSize:56,marginBottom:20,filter:"drop-shadow(0 0 24px rgba(201,169,78,0.25))"}}>{s.icon}</div>
      <h1 style={{fontSize:30,fontWeight:400,margin:"0 0 14px",fontStyle:"italic"}}>{s.title}</h1>
      <p style={{fontSize:14,color:SOFT,fontFamily:S,lineHeight:1.8,whiteSpace:"pre-line",margin:"0 0 20px",fontWeight:300}}>{s.sub}</p>
      {s.detail&&<div style={{background:CARD,border:`1px solid ${BRD}`,borderRadius:16,padding:"18px 22px",textAlign:"left",marginBottom:20,width:"100%",maxWidth:300}}>
        {s.detail.map((l,i)=><p key={i} style={{fontSize:14,color:TXT,fontFamily:S,margin:i<s.detail.length-1?"0 0 14px":"0",lineHeight:1.6,fontWeight:300}}>{l}</p>)}
      </div>}
      <button onClick={()=>step<steps.length-1?setStep(step+1):onDone()} style={{marginTop:8,padding:"13px 44px",background:GOLD,color:BG,border:"none",borderRadius:40,fontSize:14,fontFamily:S,fontWeight:500,cursor:"pointer",letterSpacing:0.5}}>
        {step<steps.length-1?"Siguiente":"Empezar"}
      </button>
      <div style={{display:"flex",gap:8,marginTop:24}}>
        {steps.map((_,i)=><div key={i} style={{width:i===step?20:8,height:6,borderRadius:3,background:i===step?GOLD:MUT,transition:"all 0.3s"}}/>)}
      </div>
    </div>
  );
}

function MissionCard({mission,idx}) {
  const [open,setOpen]=useState(false);
  return (
    <div style={{background:CARD,border:`1px solid ${BRD}`,borderRadius:14,padding:"18px 20px",marginBottom:12}}>
      <div onClick={()=>setOpen(!open)} style={{cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <p style={{fontSize:11,color:GOLD,fontFamily:S,letterSpacing:2,margin:"0 0 4px",fontWeight:500}}>SEMANA {mission.w}</p>
          <h3 style={{fontSize:18,fontFamily:T,fontStyle:"italic",margin:0,fontWeight:400}}>{mission.t}</h3>
        </div>
        <span style={{fontSize:18,color:MUT,transition:"transform 0.2s",transform:open?"rotate(180deg)":"rotate(0)"}}>{open?"▲":"▼"}</span>
      </div>
      {open&&<div style={{marginTop:14,paddingTop:14,borderTop:`1px solid ${BRD}`}}>
        <p style={{fontSize:14,color:SOFT,fontFamily:S,fontWeight:300,lineHeight:1.7,margin:"0 0 14px"}}>{mission.h}</p>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",gap:8,alignItems:"flex-start"}}>
            <span style={{fontSize:14,flexShrink:0}}>📍</span>
            <p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{mission.l}</p>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"flex-start"}}>
            <span style={{fontSize:14,flexShrink:0}}>🕐</span>
            <p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{mission.time}</p>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"flex-start"}}>
            <span style={{fontSize:14,flexShrink:0}}>💡</span>
            <p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{mission.tips}</p>
          </div>
        </div>
      </div>}
    </div>
  );
}

export default function App() {
  const [ob,setOb]=useState(()=>{try{return localStorage.getItem("lc2_ob")==="1"}catch{return false}});
  const [mode,setMode]=useState(()=>{try{return localStorage.getItem("lc2_mode")||"countdown"}catch{return "countdown"}});
  const [view,setView]=useState("today");
  const [sel,setSel]=useState(null);
  const [ul,setUl]=useState(()=>{try{return JSON.parse(localStorage.getItem("lc2_u")||"[]")}catch{return[]}});
  const t=td();

  useEffect(()=>{
    const past=D.filter(x=>x.d<=t).map(x=>x.d);
    const merged=[...new Set([...ul,...past])];
    if(merged.length!==ul.length){setUl(merged);try{localStorage.setItem("lc2_u",JSON.stringify(merged))}catch{}}
  },[t]);

  const finOb=useCallback(()=>{setOb(true);try{localStorage.setItem("lc2_ob","1")}catch{}},[]);
  const activateLondon=()=>{setMode("london");try{localStorage.setItem("lc2_mode","london")}catch{}};
  if(!ob) return <Onboarding onDone={finOb}/>;

  const todayE=D.find(x=>x.d===t);
  const detE=sel?D.find(x=>x.d===sel):null;
  const rem=daysTo();
  const months={};
  D.forEach(x=>{const m=x.d.slice(0,7);(months[m]=months[m]||[]).push(x)});

  // ── LONDON MODE (missions) ──
  if(mode==="london") {
    if(view==="mission_list") {
      return (
        <div style={{minHeight:"100vh",background:BG,color:TXT,fontFamily:T}}>
          <link href={FONTS} rel="stylesheet"/>
          <div style={{maxWidth:480,margin:"0 auto",padding:"20px 24px 60px"}}>
            <button onClick={()=>setView("today")} style={{background:"none",border:"none",color:GOLD,fontSize:14,cursor:"pointer",padding:"8px 0",fontFamily:S,marginBottom:12}}>← Inicio</button>
            <h1 style={{fontSize:24,fontStyle:"italic",margin:"0 0 4px"}}>Misiones secretas</h1>
            <p style={{color:MUT,fontSize:13,fontFamily:S,margin:"0 0 20px",fontWeight:300}}>52 semanas · 52 descubrimientos</p>
            {M.map((m,i)=><MissionCard key={i} mission={m} idx={i}/>)}
          </div>
        </div>
      );
    }
    // London home
    const currentWeek = Math.min(52, Math.max(1, Math.ceil((new Date() - new Date(2027,0,4)) / (7*86400000))));
    const currentMission = M.find(x=>x.w===currentWeek) || M[0];
    return (
      <div style={{minHeight:"100vh",background:`linear-gradient(175deg, ${BG} 0%, ${BG2} 100%)`,color:TXT,fontFamily:T}}>
        <link href={FONTS} rel="stylesheet"/>
        <div style={{maxWidth:480,margin:"0 auto",padding:"40px 24px 60px"}}>
          <div style={{textAlign:"center",marginBottom:32}}>
            <p style={{color:GOLD,fontSize:11,letterSpacing:4,textTransform:"uppercase",margin:"0 0 8px",fontFamily:S,fontWeight:500}}>Modo Londres</p>
            <h1 style={{fontSize:28,fontWeight:400,margin:"0 0 4px",fontStyle:"italic"}}>Ya están acá</h1>
            <p style={{color:MUT,fontSize:13,fontFamily:S,margin:0,fontWeight:300}}>Semana {currentWeek} de 52</p>
          </div>
          <div style={{background:CARD,borderRadius:18,padding:"24px 22px",marginBottom:16,border:`1px solid ${BRD}`}}>
            <p style={{fontSize:11,color:GOLD,fontFamily:S,letterSpacing:2,margin:"0 0 6px",fontWeight:500}}>MISIÓN DE LA SEMANA</p>
            <h2 style={{fontSize:22,fontStyle:"italic",margin:"0 0 14px",fontWeight:400}}>{currentMission.t}</h2>
            <p style={{fontSize:14,color:SOFT,fontFamily:S,fontWeight:300,lineHeight:1.7,margin:"0 0 16px"}}>{currentMission.h}</p>
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              <div style={{display:"flex",gap:8}}><span>📍</span><p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{currentMission.l}</p></div>
              <div style={{display:"flex",gap:8}}><span>🕐</span><p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{currentMission.time}</p></div>
              <div style={{display:"flex",gap:8}}><span>💡</span><p style={{fontSize:13,color:TXT,fontFamily:S,margin:0,fontWeight:300}}>{currentMission.tips}</p></div>
            </div>
          </div>
          <button onClick={()=>setView("mission_list")} style={{width:"100%",padding:"13px",background:CARD,border:`1px solid ${BRD}`,borderRadius:12,color:TXT,fontSize:14,cursor:"pointer",fontFamily:S,fontWeight:400,marginBottom:12}}>
            🗝️ Ver todas las misiones
          </button>
          <button onClick={()=>{setMode("countdown");try{localStorage.setItem("lc2_mode","countdown")}catch{}}} style={{width:"100%",padding:"13px",background:"transparent",border:`1px solid ${BRD}`,borderRadius:12,color:MUT,fontSize:13,cursor:"pointer",fontFamily:S,fontWeight:300}}>
            ← Volver al countdown
          </button>
          <p style={{textAlign:"center",color:MUT,fontSize:11,marginTop:28,fontFamily:S,letterSpacing:2}}>🇦🇷 → 🇬🇧</p>
        </div>
      </div>
    );
  }

  // ── DETAIL VIEW ──
  if(view==="detail"&&detE) {
    const op=ul.includes(detE.d);
    return (
      <div style={{minHeight:"100vh",background:BG,color:TXT,fontFamily:T}}>
        <link href={FONTS} rel="stylesheet"/>
        <div style={{maxWidth:480,margin:"0 auto",padding:"20px 24px 60px"}}>
          <button onClick={()=>setView("calendar")} style={{background:"none",border:"none",color:GOLD,fontSize:14,cursor:"pointer",padding:"8px 0",fontFamily:S,marginBottom:12}}>← Calendario</button>
          <div style={{fontSize:40,marginBottom:8}}>{detE.e}</div>
          <p style={{color:GOLD,fontSize:11,letterSpacing:3,textTransform:"uppercase",margin:"0 0 6px",fontFamily:S,fontWeight:500}}>{fmtDate(detE.d)}</p>
          <h1 style={{fontSize:26,fontWeight:700,margin:"0 0 18px",lineHeight:1.3,fontStyle:"italic"}}>{op?detE.t:"🔒 Aún no disponible"}</h1>
          {op?<p style={{fontSize:15,lineHeight:1.9,color:SOFT,fontFamily:S,fontWeight:300}}>{detE.m}</p>
            :<p style={{fontSize:14,color:MUT,fontFamily:S,fontWeight:300}}>Este dato se desbloquea el {fmtDate(detE.d)}.</p>}
          <div style={{marginTop:24,padding:"10px 14px",background:CARD,borderRadius:10,display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:16}}>{detE.e}</span>
            <span style={{color:MUT,fontSize:12,fontFamily:S,fontWeight:300}}>{CAT[detE.e]||""}</span>
          </div>
        </div>
      </div>
    );
  }

  // ── CALENDAR VIEW ──
  if(view==="calendar") {
    return (
      <div style={{minHeight:"100vh",background:BG,color:TXT,fontFamily:T}}>
        <link href={FONTS} rel="stylesheet"/>
        <div style={{maxWidth:480,margin:"0 auto",padding:"20px 24px 60px"}}>
          <button onClick={()=>setView("today")} style={{background:"none",border:"none",color:GOLD,fontSize:14,cursor:"pointer",padding:"8px 0",fontFamily:S,marginBottom:12}}>← Hoy</button>
          <h1 style={{fontSize:24,fontStyle:"italic",margin:"0 0 4px"}}>220 días</h1>
          <p style={{color:MUT,fontSize:13,margin:"0 0 24px",fontFamily:S,fontWeight:300}}>🇦🇷 → 🇬🇧</p>
          {Object.entries(months).map(([m,ents])=>(
            <div key={m} style={{marginBottom:22}}>
              <h2 style={{fontSize:15,color:GOLD,margin:"0 0 10px",letterSpacing:1.5,fontWeight:400,fontFamily:S}}>{MN[m.slice(5)]} 2026</h2>
              <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:5}}>
                {ents.map(en=>{
                  const op=ul.includes(en.d),isTd=en.d===t;
                  return <button key={en.d} onClick={()=>op&&(setSel(en.d),setView("detail"))}
                    style={{width:"100%",aspectRatio:"1",borderRadius:8,border:isTd?`2px solid ${GOLD}`:`1px solid ${BRD}`,
                      background:op?(isTd?"rgba(201,169,78,0.12)":CARD):"rgba(0,0,0,0.2)",
                      cursor:op?"pointer":"default",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:1,
                      opacity:op?1:0.3,boxShadow:isTd?`0 0 10px rgba(201,169,78,0.2)`:"none",transition:"transform 0.15s"}}
                    onMouseEnter={e=>op&&(e.currentTarget.style.transform="scale(1.08)")}
                    onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}>
                    <span style={{fontSize:13}}>{op?en.e:"🔒"}</span>
                    <span style={{fontSize:9,color:MUT,fontFamily:S}}>{parseInt(en.d.slice(8))}</span>
                  </button>;
                })}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // ── TODAY VIEW ──
  return (
    <div style={{minHeight:"100vh",background:`linear-gradient(175deg, ${BG} 0%, ${BG2} 100%)`,color:TXT,fontFamily:T}}>
      <link href={FONTS} rel="stylesheet"/>
      <div style={{maxWidth:480,margin:"0 auto",padding:"40px 24px 60px"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <p style={{color:GOLD,fontSize:11,letterSpacing:4,textTransform:"uppercase",margin:"0 0 10px",fontFamily:S,fontWeight:500}}>London Countdown</p>
          <h1 style={{fontSize:60,fontWeight:400,margin:"0 0 2px",fontStyle:"italic",color:GOLD}}>{rem>0?rem:"🎉"}</h1>
          <p style={{color:MUT,fontSize:13,margin:0,fontFamily:S,fontWeight:300}}>{rem>0?`día${rem!==1?"s":""}`:""}</p>
        </div>
        {todayE?(
          <div onClick={()=>{setSel(todayE.d);setView("detail")}}
            style={{background:CARD,borderRadius:18,padding:"24px 22px",cursor:"pointer",marginBottom:16,border:`1px solid ${BRD}`,transition:"transform 0.2s",boxShadow:`0 4px 24px rgba(201,169,78,0.06)`}}
            onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-2px)"}}
            onMouseLeave={e=>{e.currentTarget.style.transform="translateY(0)"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <span style={{fontSize:30}}>{todayE.e}</span>
              <span style={{background:`rgba(201,169,78,0.15)`,color:GOLD,padding:"3px 12px",borderRadius:16,fontSize:10,fontFamily:S,letterSpacing:1.5,fontWeight:500}}>HOY</span>
            </div>
            <p style={{color:GOLD,fontSize:11,letterSpacing:2,textTransform:"uppercase",margin:"0 0 5px",fontFamily:S,fontWeight:400}}>{fmtDate(todayE.d)}</p>
            <h2 style={{fontSize:22,fontWeight:700,margin:"0 0 10px",lineHeight:1.3,fontStyle:"italic"}}>{todayE.t}</h2>
            <p style={{fontSize:14,lineHeight:1.7,color:SOFT,margin:0,fontFamily:S,fontWeight:300,display:"-webkit-box",WebkitLineClamp:3,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{todayE.m}</p>
            <p style={{color:GOLD,fontSize:12,margin:"10px 0 0",fontFamily:S,fontWeight:400}}>Leer más →</p>
          </div>
        ):(
          <div style={{background:CARD,borderRadius:18,padding:"28px 22px",textAlign:"center",marginBottom:16,border:`1px solid ${BRD}`}}>
            <p style={{fontSize:40,margin:"0 0 8px"}}>🇬🇧</p>
            <h2 style={{fontSize:20,margin:"0 0 6px",fontStyle:"italic"}}>Hoy no hay mensaje</h2>
            <p style={{color:MUT,fontSize:13,fontFamily:S,fontWeight:300}}>26/3 al 31/10 de 2026</p>
          </div>
        )}
        <button onClick={()=>setView("calendar")} style={{width:"100%",padding:"13px",background:CARD,border:`1px solid ${BRD}`,borderRadius:12,color:TXT,fontSize:14,cursor:"pointer",fontFamily:S,fontWeight:400,marginBottom:10,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}
          onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.07)"}
          onMouseLeave={e=>e.currentTarget.style.background=CARD}>
          📅 Ver los 220 días
        </button>
        <button onClick={activateLondon} style={{width:"100%",padding:"13px",background:"rgba(201,169,78,0.08)",border:`1px solid rgba(201,169,78,0.2)`,borderRadius:12,color:GOLD,fontSize:14,cursor:"pointer",fontFamily:S,fontWeight:500,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
          🗝️ Activar Modo Londres
        </button>
        <div style={{marginTop:18}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
            <span style={{fontSize:11,color:MUT,fontFamily:S,fontWeight:300}}>Progreso</span>
            <span style={{fontSize:11,color:GOLD,fontFamily:S,fontWeight:400}}>{ul.length} / 220</span>
          </div>
          <div style={{height:3,background:BRD,borderRadius:2,overflow:"hidden"}}>
            <div style={{height:"100%",width:`${(ul.length/220)*100}%`,background:`linear-gradient(90deg, ${GOLD}, ${GOLD}88)`,borderRadius:2,transition:"width 0.5s"}}/>
          </div>
        </div>
        <p style={{textAlign:"center",color:MUT,fontSize:11,marginTop:28,fontFamily:S,letterSpacing:2,fontWeight:300}}>🇦🇷 → 🇬🇧</p>
      </div>
    </div>
  );
}
